90	/**
91	 * Determine which besieging faction captures the city.
92	 * Returns the faction with the most adjacent units.
93	 */
94	export function getCapturingFaction(
95	  city: City,
96	  state: GameState
97	): FactionId | null {
98	  const adjacentCounts = new Map<FactionId, number>();
99	  const neighbors = getHexesInRange(city.position, 1)
100	    .filter(h => !(h.q === city.position.q && h.r === city.position.r));
101	
102	  for (const hex of neighbors) {
103	    for (const [, unit] of state.units) {
104	      if (
105	        unit.hp > 0 &&
106	        unit.position.q === hex.q &&
107	        unit.position.r === hex.r &&
108	        unit.factionId !== city.factionId
109	      ) {
110	        adjacentCounts.set(
111	          unit.factionId,
112	          (adjacentCounts.get(unit.factionId) ?? 0) + 1
113	        );
114	      }
115	    }
116	  }
117	
118	  if (adjacentCounts.size === 0) return null;
119	
120	  let maxFaction: FactionId | null = null;
121	  let maxCount = 0;
122	  for (const [factionId, count] of adjacentCounts) {
123	    if (count > maxCount) {
124	      maxCount = count;
125	      maxFaction = factionId;
126	    }
127	  }
128	  return maxFaction;
129	}
