6	/**
7	 * Activation state for alternating unit activation.
8	 * Tracks the interleaved queue of units to activate this round.
9	 */
10	export interface ActivationState {
11	  queue: UnitId[];
12	  index: number;
13	}
14	
15	/**
16	 * Get the currently active faction
17	 */
18	export function getActiveFaction(gameState: GameState): Faction | null {
19	  if (!gameState.activeFactionId) return null;
20	  return gameState.factions.get(gameState.activeFactionId) ?? null;
21	}
22	
23	/**
24	 * Check if it's a specific faction's turn
25	 */
26	export function isFactionTurn(gameState: GameState, factionId: FactionId): boolean {
27	  return gameState.activeFactionId === factionId;
28	}
29	
30	/**
31	 * Reset moves and attacks for all units of a faction to their max
32	 */
33	function resetFactionUnitsMoves(
34	  units: Map<UnitId, Unit>,
35	  factionId: FactionId
36	): Map<UnitId, Unit> {
37	  const newUnits = new Map(units);
38	  for (const [unitId, unit] of units) {
39	    if (unit.factionId === factionId) {
40	      newUnits.set(unitId, {
41	        ...unit,
42	        movesRemaining: unit.maxMoves,
43	        attacksRemaining: 1,
44	        status: 'ready',
45	        enteredZoCThisActivation: false,
46	      });
47	    }
48	  }
49	  return newUnits;
50	}
51	
52	/**
53	 * Get the first faction in the factions map (for round start)
54	 */
55	function getFirstFactionId(factions: Map<FactionId, Faction>): FactionId | null {
56	  const iterator = factions.keys();
57	  const first = iterator.next();
58	  return first.done ? null : first.value;
59	}
60	
61	/**
62	 * Get the next faction in order (cycles through factions map)
63	 */
64	function getNextFactionId(
65	  factions: Map<FactionId, Faction>,
66	  currentFactionId: FactionId
67	): FactionId | null {
68	  const factionIds = Array.from(factions.keys());
69	  const currentIndex = factionIds.indexOf(currentFactionId);
70	  
71	  if (currentIndex === -1 || factionIds.length === 0) return null;
72	  
73	  const nextIndex = (currentIndex + 1) % factionIds.length;
74	  return factionIds[nextIndex];
75	}
76	
77	/**
78	 * Advance to the next faction's turn
79	 * After all factions have taken a turn, increment the round
80	 * Reset the new active faction's units' movesRemaining
81	 */
82	export function advanceTurn(gameState: GameState): GameState {
83	  const factions = gameState.factions;
84	  
85	  // If no active faction, start at the first one
86	  if (!gameState.activeFactionId) {
87	    const firstFactionId = getFirstFactionId(factions);
88	    if (!firstFactionId) return gameState; // No factions in game
89	    
90	    return {
91	      ...gameState,
92	      round: 1,
93	      turnNumber: 1,
94	      activeFactionId: firstFactionId,
95	      units: resetFactionUnitsMoves(gameState.units, firstFactionId),
96	    };
97	  }
98	  
99	  const currentFactionId = gameState.activeFactionId;
100	  const nextFactionId = getNextFactionId(factions, currentFactionId);
101	  
102	  if (!nextFactionId) return gameState; // No factions
103	  
104	  const isNewRound = nextFactionId === getFirstFactionId(factions);
105	  
106	  const newUnits = resetFactionUnitsMoves(gameState.units, nextFactionId);
107	  
108	  return {
109	    ...gameState,
110	    round: isNewRound ? gameState.round + 1 : gameState.round,
111	    turnNumber: gameState.turnNumber + 1,
112	    activeFactionId: nextFactionId,
113	    units: newUnits,
114	  };
115	}
116	
117	// ─── Alternating Unit Activation ────────────────────────────────────────────
118	
119	/**
120	 * Reset all units across all factions for a new round.
121	 * Clears activatedThisRound, restores moves/attacks, recovers morale.
122	 */
123	export function resetAllUnitsForRound(state: GameState): GameState {
124	  const newUnits = new Map(state.units);
125	  for (const [unitId, unit] of newUnits) {
126	    if (unit.hp <= 0) continue;
127	      newUnits.set(unitId, {
128	        ...unit,
129	        movesRemaining: unit.maxMoves,
130	        attacksRemaining: 1,
131	        status: 'ready' as const,
132	        activatedThisRound: false,
133	        enteredZoCThisActivation: false,
134	      });
135	  }
136	  return { ...state, units: newUnits };
137	}
138	
139	/**
140	 * Build an interleaved activation queue from all factions' living units.
141	 * Option A: round-robin one unit per faction, extras go at the end.
142	 */
143	export function buildActivationQueue(state: GameState): ActivationState {
144	  const factionIds = Array.from(state.factions.keys());
145	
146	  // Collect living units per faction
147	  const unitsByFaction: Map<FactionId, UnitId[]> = new Map();
148	  for (const factionId of factionIds) {
149	    unitsByFaction.set(factionId, []);
150	  }
151	  for (const [unitId, unit] of state.units) {
152	    if (unit.hp > 0) {
153	      const list = unitsByFaction.get(unit.factionId);
154	      if (list) list.push(unitId);
155	    }
156	  }
157	
158	  // Interleave: take one from each faction in order, repeat
159	  const queue: UnitId[] = [];
160	  const indices: Map<FactionId, number> = new Map();
161	  for (const factionId of factionIds) {
162	    indices.set(factionId, 0);
163	  }
164	
165	  let added = true;
166	  while (added) {
167	    added = false;
168	    for (const factionId of factionIds) {
169	      const units = unitsByFaction.get(factionId)!;
170	      const idx = indices.get(factionId)!;
171	      if (idx < units.length) {
172	        queue.push(units[idx]);
173	        indices.set(factionId, idx + 1);
174	        added = true;
175	      }
176	    }
177	  }
178	
179	  return { queue, index: 0 };
180	}
181	
182	/**
183	 * Get the next unit to activate from the queue.
184	 * Skips dead units and already-activated units.
185	 * Returns { unitId, factionId } or null when queue is exhausted.
186	 */
187	export function nextUnitActivation(
188	  state: GameState,
189	  activation: ActivationState
190	): { unitId: UnitId; factionId: FactionId } | null {
191	  while (activation.index < activation.queue.length) {
192	    const unitId = activation.queue[activation.index];
193	    activation.index++;
194	
195	    const unit = state.units.get(unitId);
196	    if (!unit || unit.hp <= 0 || unit.activatedThisRound) continue;
197	
198	    return { unitId, factionId: unit.factionId };
199	  }
200	
201	  return null;
202	}

