102	function isPirateLandUnit(unit: Pick<UnitView, 'factionId' | 'movementClass'>): boolean {
103	  return unit.factionId === 'coral_people' && unit.movementClass !== 'naval';
104	}
105	
106	function isPirateNavalUnit(unit: Pick<UnitView, 'factionId' | 'movementClass'>): boolean {
107	  return unit.factionId === 'coral_people' && unit.movementClass === 'naval';
108	}
109	
110	function isPirateBaseInfantry(attacker: Pick<UnitView, 'factionId' | 'chassisId' | 'movementClass' | 'range'>): boolean {
111	  return attacker.factionId === 'coral_people'
112	    && attacker.chassisId === 'infantry_frame'
113	    && attacker.movementClass === 'infantry'
114	    && isMeleeRange(attacker);
115	}
116	
117	function isMeleeRange(unit: Pick<UnitView, 'range'>): boolean {
118	  return (unit.range ?? 1) <= 1;
119	}
