121	function classifyCombatSound(attacker: Pick<UnitView, 'factionId' | 'prototypeId' | 'chassisId' | 'movementClass' | 'role' | 'range'>): SoundId | null {
122	  // ── Special summon/beast units (most specific) ──
123	  if (attacker.chassisId === 'polar_bear_frame') {
124	    return 'polar_bear';
125	  }
126	  if (attacker.chassisId === 'serpent_frame') {
127	    return 'serpent_god';
128	  }
129	  if (attacker.chassisId === 'alligator_frame') {
130	    return 'crocodile';
131	  }
132	  if (attacker.chassisId === 'chariot_frame') {
133	    return 'chariot';
134	  }
135	
136	  // ── Siege / existing special ──
137	  if (attacker.chassisId === 'catapult_frame' || attacker.prototypeId.includes('catapult')) {
138	    return 'catapult';
139	  }
140	  if (attacker.chassisId === 'elephant_frame' || attacker.prototypeId.includes('elephant')) {
141	    return 'elephant';
142	  }
143	
144	  // ── Magic / spellcaster units ──
145	  if (attacker.prototypeId === 'druid_wizard') {
146	    return 'wizard_spell';
147	  }
148	  if (attacker.prototypeId.includes('_priest')) {
149	    return 'priest_spell';
150	  }
151	  if (attacker.prototypeId === 'blowgun_skirmishers') {
152	    return 'blowgun';
153	  }
154	
155	  // ── Naval units ──
156	  if (isPirateNavalUnit(attacker)) {
157	    return 'pirate_galley';
158	  }
159	  if (attacker.movementClass === 'naval') {
160	    return 'naval_battle';
161	  }
162	
163	  // ── Pirate land units ──
164	  if (isPirateBaseInfantry(attacker)) {
165	    return 'melee_infantry';
166	  }
167	  if (isPirateLandUnit(attacker)) {
168	    return 'pirate_gun';
169	  }
170	
171	  if (attacker.factionId === 'steppe_clan' && attacker.chassisId === 'cavalry_frame') {
172	    return 'ranged';
173	  }
174	
175	  // ── Ranged (non-pirate) ──
176	  if (attacker.role === 'ranged' && attacker.factionId !== 'coral_people') {
177	    return 'ranged';
178	  }
179	
180	  // ── Melee fallbacks ──
181	  if (isMeleeRange(attacker) && ['cavalry', 'camel'].includes(attacker.movementClass ?? '')) {
182	    return 'melee_cavalry';
183	  }
184	  if (isMeleeRange(attacker) && attacker.movementClass === 'infantry') {
185	    return 'melee_infantry';
186	  }
187	
188	  return null;
189	}
