198	function buildAudioSnapshot(state: ClientState): AudioSnapshot | null {
199	  if (state.mode !== 'play' || !state.playFeedback) {
200	    return null;
201	  }
202	
203	  const playerFactionId = state.playFeedback.playerFactionId;
204	  const cityOwners = new Map(state.world.cities.map((city) => [city.id, city.factionId]));
205	  const unitOwners = new Map(state.world.units.map((unit) => [unit.id, unit.factionId]));
206	  const villages = new Map(state.world.villages.map((village) => [village.id, { factionId: village.factionId, name: village.name }]));
207	  const suppressedVillageLossIds = state.playFeedback.lastSettlerVillageSpend?.factionId === playerFactionId
208	    ? new Set(state.playFeedback.lastSettlerVillageSpend.villageIds)
209	    : new Set<string>();
210	  const playerCityCount = playerFactionId
211	    ? state.world.cities.filter((city) => city.factionId === playerFactionId).length
212	    : 0;
213	  const playerWon = Boolean(
214	    playerFactionId
215	      && state.playFeedback.victory?.winnerFactionId === playerFactionId
216	      && state.playFeedback.victory.victoryType !== 'unresolved',
217	  );
218	
219	  return {
220	    moveCount: state.playFeedback.moveCount,
221	    lastMoveUnitId: state.playFeedback.lastMove?.unitId ?? null,
222	    lastSacrificeKey: state.playFeedback.lastSacrifice
223	      ? `${state.playFeedback.lastSacrifice.unitId}:${state.playFeedback.lastSacrifice.domains.join(',')}`
224	      : null,
225	    lastLearnedDomainKey: state.playFeedback.lastLearnedDomain
226	      ? `${state.playFeedback.lastLearnedDomain.unitId}:${state.playFeedback.lastLearnedDomain.domainId}`
227	      : null,
228	    lastResearchCompletionKey: state.playFeedback.lastResearchCompletion
229	      ? `${state.playFeedback.lastResearchCompletion.nodeId}:${state.playFeedback.lastResearchCompletion.tier}`
230	      : null,
231	    hitAndRunRetreatKey: state.playFeedback.hitAndRunRetreat
232	      ? `${state.playFeedback.hitAndRunRetreat.unitId}:${state.playFeedback.hitAndRunRetreat.to.q},${state.playFeedback.hitAndRunRetreat.to.r}`
233	      : null,
234	    suppressedVillageLossIds,
235	    playerCityCount,
236	    playerFactionId,
237	    cityOwners,
238	    unitOwners,
239	    villages,
240	    playerWon,
241	  };
242	}
