20	    for (const city of world.cities) {
21	      const point = this.worldToScreen(city.q, city.r);
22	      const factionColor = Phaser.Display.Color.HexStringToColor(world.factions.find((faction) => faction.id === city.factionId)?.color ?? '#c8b68e').color;
23	      const backing = this.scene.add.ellipse(point.x, point.y - 16, 58, 30, 0x120f0c, 0.72)
24	        .setStrokeStyle(3, factionColor, 0.82);
25	      this.layer.add(backing);
26	      const sprite = this.scene.add.image(point.x, point.y - 6, TEXTURES.cities, getSettlementFrame(city.factionId, 'city'))
27	        .setOrigin(0.5, 1)
28	        .setInteractive({ cursor: 'pointer' });
29	      sprite.on('pointerdown', (pointer: Phaser.Input.Pointer) => callbacks.onCitySelected(city.id, pointer));
30	      this.layer.add(sprite);
