198	function buildAudioSnapshot(state: ClientState): AudioSnapshot | null {
199	  if (state.mode !== 'play' || !state.playFeedback) {
200	    return null;
201	  }
202	
203	  const playerFactionId = state.playFeedback.playerFactionId;
204	  const cityOwners = new Map(state.world.cities.map((city) => [city.id, city.factionId]));
205	  const unitOwners = new Map(state.world.units.map((unit) => [unit.id, unit.factionId]));
206	  const villages = new Map(state.world.villages.map((village) => [village.id, { factionId: village.factionId, name: village.name }]));
207	  const suppressedVillageLossIds = state.playFeedback.lastSettlerVillageSpend?.factionId === playerFactionId
208	    ? new Set(state.playFeedback.lastSettlerVillageSpend.villageIds)
209	    : new Set<string>();
210	  const playerCityCount = playerFactionId
211	    ? state.world.cities.filter((city) => city.factionId === playerFactionId).length
212	    : 0;
213	  const playerWon = Boolean(
214	    playerFactionId
215	      && state.playFeedback.victory?.winnerFactionId === playerFactionId
216	      && state.playFeedback.victory.victoryType !== 'unresolved',
217	  );
218	
219	  return {
220	    moveCount: state.playFeedback.moveCount,
221	    lastMoveUnitId: state.playFeedback.lastMove?.unitId ?? null,
222	    lastSacrificeKey: state.playFeedback.lastSacrifice
223	      ? `${state.playFeedback.lastSacrifice.unitId}:${state.playFeedback.lastSacrifice.domains.join(',')}`
224	      : null,
225	    lastLearnedDomainKey: state.playFeedback.lastLearnedDomain
226	      ? `${state.playFeedback.lastLearnedDomain.unitId}:${state.playFeedback.lastLearnedDomain.domainId}`
227	      : null,
228	    lastResearchCompletionKey: state.playFeedback.lastResearchCompletion
229	      ? `${state.playFeedback.lastResearchCompletion.nodeId}:${state.playFeedback.lastResearchCompletion.tier}`
230	      : null,
231	    hitAndRunRetreatKey: state.playFeedback.hitAndRunRetreat
232	      ? `${state.playFeedback.hitAndRunRetreat.unitId}:${state.playFeedback.hitAndRunRetreat.to.q},${state.playFeedback.hitAndRunRetreat.to.r}`
233	      : null,
234	    suppressedVillageLossIds,
235	    playerCityCount,
236	    playerFactionId,
237	    cityOwners,
238	    unitOwners,
239	    villages,
240	    playerWon,
241	  };
242	}
243	
244	export function getDestroyedPlayerVillages(prevState: ClientState | null, nextState: ClientState): string[] {
245	  const prev = prevState ? buildAudioSnapshot(prevState) : null;
246	  const next = buildAudioSnapshot(nextState);
247	
248	  if (!prev || !next || !prev.playerFactionId) {
249	    return [];
250	  }
251	
252	  const destroyed: string[] = [];
253	  for (const [villageId, village] of prev.villages.entries()) {
254	    if (village.factionId !== prev.playerFactionId) {
255	      continue;
256	    }
257	    if (!next.villages.has(villageId) && !next.suppressedVillageLossIds.has(villageId)) {
258	      destroyed.push(village.name);
259	    }
260	  }
261	
262	  return destroyed;
263	}
264	
265	export function playSessionDeltaSounds(prevState: ClientState | null, nextState: ClientState) {
266	  const prev = prevState ? buildAudioSnapshot(prevState) : null;
267	  const next = buildAudioSnapshot(nextState);
268	
269	  if (!prev || !next) {
270	    return;
271	  }
272	
273	  if (next.moveCount > prev.moveCount) {
274	    playSound('move');
275	  }
276	
277	  if (next.lastSacrificeKey && next.lastSacrificeKey !== prev.lastSacrificeKey) {
278	    playSound('sacrifice');
279	  }
280	
281	  if (next.lastLearnedDomainKey && next.lastLearnedDomainKey !== prev.lastLearnedDomainKey) {
282	    playSound('learned_domain');
283	  }
284	
285	  if (next.lastResearchCompletionKey && next.lastResearchCompletionKey !== prev.lastResearchCompletionKey) {
286	    playSound('research_tier');
287	  }
288	
289	  if (next.hitAndRunRetreatKey && next.hitAndRunRetreatKey !== prev.hitAndRunRetreatKey) {
290	    playSound('hit_and_run');
291	  }
292	
293	  if ([...next.cityOwners.keys()].some((cityId) => !prev.cityOwners.has(cityId))) {
294	    playSound('city_built');
295	  }
296	
297	  if ([...next.cityOwners.entries()].some(([cityId, factionId]) => {
298	    const previousOwner = prev.cityOwners.get(cityId);
299	    return previousOwner !== undefined && previousOwner !== factionId;
300	  })) {
301	    playSound('city_captured');
302	  }
303	
304	  if ([...next.unitOwners.entries()].some(([unitId, factionId]) => {
305	    const previousOwner = prev.unitOwners.get(unitId);
306	    return previousOwner !== undefined && previousOwner !== factionId;
307	  })) {
308	    playSound('slaver_capture');
309	  }
310	
311	  if (getDestroyedPlayerVillages(prevState, nextState).length > 0) {
312	    playSound('village_destroyed');
313	  }
314	
315	  if (prev.playerCityCount > 0 && next.playerCityCount === 0) {
316	    playSound('defeat');
317	  }
318	
319	  if (!prev.playerWon && next.playerWon) {
320	    playSound('victory');
321	  }
322	}

