244	export function getDestroyedPlayerVillages(prevState: ClientState | null, nextState: ClientState): string[] {
245	  const prev = prevState ? buildAudioSnapshot(prevState) : null;
246	  const next = buildAudioSnapshot(nextState);
247	
248	  if (!prev || !next || !prev.playerFactionId) {
249	    return [];
250	  }
251	
252	  const destroyed: string[] = [];
253	  for (const [villageId, village] of prev.villages.entries()) {
254	    if (village.factionId !== prev.playerFactionId) {
255	      continue;
256	    }
257	    if (!next.villages.has(villageId) && !next.suppressedVillageLossIds.has(villageId)) {
258	      destroyed.push(village.name);
259	    }
260	  }
261	
262	  return destroyed;
263	}
264	
265	export function playSessionDeltaSounds(prevState: ClientState | null, nextState: ClientState) {
266	  const prev = prevState ? buildAudioSnapshot(prevState) : null;
267	  const next = buildAudioSnapshot(nextState);
268	
269	  if (!prev || !next) {
270	    return;
271	  }
272	
273	  if (next.moveCount > prev.moveCount) {
274	    playSound('move');
275	  }
276	
277	  if (next.lastSacrificeKey && next.lastSacrificeKey !== prev.lastSacrificeKey) {
278	    playSound('sacrifice');
279	  }
280	
281	  if (next.lastLearnedDomainKey && next.lastLearnedDomainKey !== prev.lastLearnedDomainKey) {
282	    playSound('learned_domain');
283	  }
284	
285	  if (next.lastResearchCompletionKey && next.lastResearchCompletionKey !== prev.lastResearchCompletionKey) {
286	    playSound('research_tier');
287	  }
288	
289	  if (next.hitAndRunRetreatKey && next.hitAndRunRetreatKey !== prev.hitAndRunRetreatKey) {
290	    playSound('hit_and_run');
291	  }
292	
293	  if ([...next.cityOwners.keys()].some((cityId) => !prev.cityOwners.has(cityId))) {
294	    playSound('city_built');
295	  }
296	
297	  if ([...next.cityOwners.entries()].some(([cityId, factionId]) => {
298	    const previousOwner = prev.cityOwners.get(cityId);
299	    return previousOwner !== undefined && previousOwner !== factionId;
300	  })) {
301	    playSound('city_captured');
302	  }
303	
304	  if ([...next.unitOwners.entries()].some(([unitId, factionId]) => {
305	    const previousOwner = prev.unitOwners.get(unitId);
306	    return previousOwner !== undefined && previousOwner !== factionId;
307	  })) {
308	    playSound('slaver_capture');
309	  }
310	
311	  if (getDestroyedPlayerVillages(prevState, nextState).length > 0) {
312	    playSound('village_destroyed');
313	  }
314	
315	  if (prev.playerCityCount > 0 && next.playerCityCount === 0) {
316	    playSound('defeat');
317	  }
318	
319	  if (!prev.playerWon && next.playerWon) {
320	    playSound('victory');
321	  }
322	}

