1	import { useEffect, useRef, useState } from 'react';
2	import { EventToast } from './EventToast';
3	
4	type EventToastStackProps = {
5	  events: Array<{ sequence?: number; round: number; kind?: 'move' | 'turn'; message: string }>;
6	};
7	
8	type VisibleEvent = {
9	  id: number;
10	  round: number;
11	  kind?: 'move' | 'turn';
12	  message: string;
13	};
14	
15	export function EventToastStack({ events }: EventToastStackProps) {
16	  const [visible, setVisible] = useState<VisibleEvent[]>([]);
17	  const lastSeqRef = useRef(-1);
18	
19	  useEffect(() => {
20	    const newEvents = events.filter((e) => (e.sequence ?? 0) > lastSeqRef.current);
21	    if (newEvents.length === 0) return;
22	
23	    lastSeqRef.current = Math.max(...newEvents.map((e) => e.sequence ?? 0));
24	
25	    const added: VisibleEvent[] = newEvents.map((e, i) => ({
26	      id: Date.now() + i,
27	      round: e.round,
28	      kind: e.kind,
29	      message: e.message,
30	    }));
31	
32	    setVisible((prev) => [...added, ...prev].slice(0, 4));
33	
34	    // Auto-dismiss each after 2400ms
35	    for (const item of added) {
36	      setTimeout(() => {
37	        setVisible((prev) => prev.filter((v) => v.id !== item.id));
38	      }, 2400);
39	    }
40	  }, [events]);
41	
42	  if (visible.length === 0) return null;
43	
44	  return <EventToast events={visible} />;
45	}

