2	// Handles wall degradation during siege, wall repair when safe,
3	// and city capture when walls are breached and city is encircled.
4	
5	import type { GameState } from '../game/types.js';
6	import type { City } from '../features/cities/types.js';
7	import type { FactionId } from '../types.js';
8	import { isCityEncircled } from './territorySystem.js';
9	import { getHexesInRange, hexDistance } from '../core/grid.js';
10	import {
11	  addExhaustion,
12	  EXHAUSTION_CONFIG,
13	} from './warExhaustionSystem.js';
14	import { syncFactionSettlementIds } from './factionOwnershipSystem.js';
15	
16	export const SIEGE_CONFIG = {
17	  WALL_DAMAGE_PER_TURN: 20,
18	  WALL_REPAIR_PER_TURN: 3,
19	  CAPTURED_WALL_HP_PERCENT: 50,
20	};
21	
22	/**
23	 * Apply wall damage to a besieged city.
24	 * Pirate Lords (coral_people) have Coastal Walls: half wall damage.
25	 */
26	export function degradeWalls(city: City, isCoastalWalls = false): City {
27	  if (!city.besieged) return city;
28	  const damage = isCoastalWalls
29	    ? Math.ceil(SIEGE_CONFIG.WALL_DAMAGE_PER_TURN / 2)
30	    : SIEGE_CONFIG.WALL_DAMAGE_PER_TURN;
31	  return {
32	    ...city,
33	    wallHP: Math.max(0, city.wallHP - damage),
34	  };
35	}
36	
37	/**
38	 * Repair walls when not besieged.
39	 */
40	export function repairWalls(city: City): City {
41	  if (city.besieged) return city;
42	  if (city.wallHP >= city.maxWallHP) return city;
43	  return {
44	    ...city,
45	    wallHP: Math.min(city.maxWallHP, city.wallHP + SIEGE_CONFIG.WALL_REPAIR_PER_TURN),
46	  };
47	}
48	
49	/**
50	 * Get wall defense bonus for a city at a given position.
51	 * Returns floor(wallHP / 20), range 0-5.
52	 * Pirate Lords (coral_people) multiply the bonus by wallDefenseMultiplier,
53	 * but only for their capital (starting city).
54	 */
55	export function getWallDefenseBonus(state: GameState, position: { q: number; r: number }, wallDefenseMultiplier: number = 2): number {
56	  for (const [, city] of state.cities) {
57	    if (city.position.q === position.q && city.position.r === position.r) {
58	      let bonus = Math.floor(city.wallHP / 20);
59	      // Pirate Lords: multiplied wall defense on capital only (coastal fortress)
60	      if (city.factionId === 'coral_people' && city.isCapital) {
61	        bonus *= wallDefenseMultiplier;
62	      }
63	      return bonus;
64	    }
65	  }
66	  return 0;
67	}
68	
69	/**
70	 * Check if a city has a defending garrison (friendly units on or adjacent to the city).
71	 * Defenders block capture even when walls are breached.
72	 */
73	export function hasDefendingGarrison(city: City, state: GameState): boolean {
74	  for (const [, unit] of state.units) {
75	    if (unit.factionId !== city.factionId || unit.hp <= 0) continue;
76	    const dist = hexDistance(unit.position, city.position);
77	    if (dist <= 1) return true;
78	  }
79	  return false;
80	}
81	
82	/**
83	 * Check if city is vulnerable to capture.
84	 * Requires: walls breached AND city still encircled AND no defending garrison.
85	 */
86	export function isCityVulnerable(city: City, state: GameState): boolean {
87	  return city.wallHP <= 0 && isCityEncircled(city, state) && !hasDefendingGarrison(city, state);
88	}
