405	
406	    const key = `${coord.q},${coord.r}`;
407	    const selectedUnitId = state.actions.selectedUnitId;
408	
409	    // Right-click on a unit → select it (shows side popout)
410	    const clickedUnit = state.world.units.find((u) => u.q === coord.q && u.r === coord.r);
411	    if (clickedUnit) {
412	      this.controller.dispatch({ type: 'select_unit', unitId: clickedUnit.id });
413	      return;
414	    }
415	
416	    // Right-click on a legal move destination → move the selected unit
417	    if (selectedUnitId) {
418	      const target = state.actions.legalMoves.find((hex) => hex.key === key);
419	      if (target) {
420	        this.controller.dispatch({
421	          type: 'move_unit',
422	          unitId: selectedUnitId,
423	          destination: { q: target.q, r: target.r },
424	        });
425	        return;
426	      }
427	
428	      // Right-click beyond reachable range → queue multi-turn move
429	      const clickedHex = state.world.map.hexes.find((h) => h.key === key);
430	      if (clickedHex && (clickedHex.visibility === 'visible' || clickedHex.visibility === 'explored')) {
431	        this.controller.dispatch({
432	          type: 'queue_move',
433	          unitId: selectedUnitId,
434	          destination: { q: coord.q, r: coord.r },
435	        });
436	        return;
437	      }
438	    }
439	
440	    // Right-click on empty tile with no unit selected → tile popout
441	    // Right-click elsewhere → deselect
442	    if (!selectedUnitId) {
443	      this.controller.dispatch({ type: 'select_hex', q: coord.q, r: coord.r });
444	    } else {
445	      this.controller.dispatch({ type: 'select_hex', q: -1, r: -1 });
446	    }
447	  }
448	
449	  /** Check if a pointer event is a right-click (button 2) */
450	  private static isRightClick(pointer?: Phaser.Input.Pointer): boolean {
451	    return pointer?.event instanceof MouseEvent && pointer.event.button === 2;
452	  }
453	
454	  /** Detect double-click on the same hex (within 400ms) */
455	  private isDoubleClick(key: string): boolean {
456	    const now = performance.now();
457	    const isDbl = now - this.lastLeftClickTime < 400 && this.lastLeftClickKey === key;
458	    this.lastLeftClickTime = now;
459	    this.lastLeftClickKey = key;
460	    return isDbl;
461	  }
462	
463	  /** Find a city at the given hex coordinates */
464	  private findCityAtHex(state: ClientState, q: number, r: number) {
465	    return state.world.cities.find((c) => c.q === q && c.r === r);
466	  }
