60	  dispatch(action: GameAction) {
61	    switch (action.type) {
62	      case 'select_hex':
63	        this.targetingMode = 'move';
64	        this.focusedUnitId = null;
65	        this.selected = action.q === -1 && action.r === -1
66	          ? null
67	          : { type: 'hex', q: action.q, r: action.r, key: `${action.q},${action.r}` };
68	        this.productionPopupCityId = null;
69	        break;
70	      case 'select_unit':
71	        this.targetingMode = 'move';
72	        this.selected = { type: 'unit', unitId: action.unitId };
73	        this.productionPopupCityId = null;
74	        this.requestInspectorOpen();
75	        break;
76	      case 'focus_unit':
77	        this.targetingMode = 'move';
78	        this.focusedUnitId = action.unitId;
79	        this.selected = null;
80	        this.productionPopupCityId = null;
81	        break;
82	      case 'select_city':
83	        this.targetingMode = 'move';
84	        this.selected = { type: 'city', cityId: action.cityId };
85	        this.productionPopupCityId = null;
86	        this.requestInspectorOpen();
87	        break;
88	      case 'open_city_production':
89	        this.targetingMode = 'move';
90	        this.selected = { type: 'city', cityId: action.cityId };
91	        this.productionPopupCityId = action.cityId;
92	        this.requestInspectorOpen();
93	        break;
94	      case 'close_city_production':
95	        this.productionPopupCityId = null;
96	        break;
97	      case 'select_village':
98	        this.targetingMode = 'move';
99	        this.selected = { type: 'village', villageId: action.villageId };
100	        this.requestInspectorOpen();
101	        break;
102	      case 'set_city_production':
103	        if (this.session) {
104	          this.session.dispatch(action);
105	          this.targetingMode = 'move';
106	          this.selected = { type: 'city', cityId: action.cityId };
107	        }
108	        break;
109	      case 'cancel_city_production':
110	      case 'remove_from_queue':
111	        if (this.session) {
112	          this.session.dispatch(action);
113	        }
114	        break;
115	      case 'set_targeting_mode':
116	        this.targetingMode = action.mode;
117	        break;
118	      case 'move_unit':
119	        if (this.session) {
120	          // Clear any existing queue before issuing direct move
121	          const existingUnit = this.session.getState().units.get(action.unitId as never);
122	          if (existingUnit?.moveQueueDestination) {
123	            this.session.dispatch({ type: 'cancel_queue', unitId: action.unitId });
124	          }
125	          this.session.dispatch(action);
126	          this.targetingMode = 'move';
127	          this.selected = { type: 'unit', unitId: action.unitId };
128	        }
129	        break;
130	      case 'queue_move':
131	        if (this.session) {
132	          this.session.dispatch(action);
133	          this.targetingMode = 'move';
134	          this.selected = { type: 'unit', unitId: action.unitId };
135	        }
136	        break;
137	      case 'cancel_queue':
138	        if (this.session) {
139	          this.session.dispatch(action);
140	        }
141	        break;
142	      case 'prepare_ability':
143	      case 'board_transport':
144	      case 'disembark_unit':
145	      case 'build_fort':
146	        if (this.session) {
147	          this.clearQueueIfNeeded(action.unitId);
148	          this.session.dispatch(action);
149	          this.targetingMode = 'move';
150	          this.selected = { type: 'unit', unitId: action.unitId };
151	        }
152	        break;
153	      case 'build_city':
154	        if (this.session) {
155	          this.clearQueueIfNeeded(action.unitId);
156	          const unit = this.session.getState().units.get(action.unitId as never);
157	          const position = unit ? { ...unit.position } : null;
158	          this.session.dispatch(action);
159	          this.targetingMode = 'move';
160	
161	          if (position) {
162	            const city = Array.from(this.session.getState().cities.values()).find(
163	              (entry) => entry.position.q === position.q && entry.position.r === position.r,
164	            );
165	            this.selected = city ? { type: 'city', cityId: city.id } : null;
166	            if (city) {
167	              this.requestInspectorOpen();
168	            }
169	          } else {
170	            this.selected = null;
171	          }
172	        }
173	        break;
174	      case 'attack_unit':
175	        if (this.session) {
176	          this.clearQueueIfNeeded(action.attackerId);
177	          this.session.dispatch(action);
178	          const pending = this.session.getPendingCombat();
179	          if (pending) {
180	            // Signal to start animation — don't emit until animation completes
181	            this.combatPendingListener?.(pending);
182	          } else {
183	            // Fallback: should not happen, but emit if no pending
184	            this.emit();
185	          }
186	        }
187	        break;
188	      case 'end_turn':
189	        if (this.session) {
190	          this.session.dispatch(action);
191	          this.targetingMode = 'move';
192	          this.clearSelectionIfInactive();
193	          // Process any AI combats queued during AI turn processing
194	          this.startAiCombats();
195	        } else if (this.replay) {
196	          this.turnIndex = Math.min(this.replay.turns.length - 1, this.turnIndex + 1);
197	        }
198	        break;
199	      case 'set_replay_turn':
200	        if (this.replay) {
201	          this.turnIndex = Math.max(0, Math.min(this.replay.turns.length - 1, action.turnIndex));
202	        }
203	        break;
204	      case 'start_research':
205	      case 'cancel_research':
206	        if (this.session) {
207	          this.session.dispatch(action);
208	        }
209	        break;
210	      case 'sacrifice_unit':
211	        if (this.session) {
212	          this.clearQueueIfNeeded(action.unitId);
213	          this.session.dispatch(action);
214	        }
215	        break;
216	      default:
217	        return;
218	    }
219	
220	    this.emit();
221	  }
