499	
500	  const hoveredMove = legalMoves.find((entry) => entry.key === hoveredKey);
501	  if (!hoveredMove) {
502	    return [];
503	  }
504	
505	  return hoveredMove.path.map((node, index) => ({
506	    key: `${node.q},${node.r}`,
507	    q: node.q,
508	    r: node.r,
509	    step: index,
510	  }));
