513	function describePlayHint(
514	  world: ClientState['world'],
515	  selectedUnitId: string | null,
516	  targetingMode: 'move' | 'attack',
517	  legalMoveCount: number,
518	  attackTargetCount: number,
519	) {
520	  if (!selectedUnitId) {
521	    return 'Select a friendly unit to move, or press A after selecting one to target an attack.';
522	  }
523	
524	  const unit = world.units.find((entry) => entry.id === selectedUnitId);
525	  if (!unit) {
526	    return 'Select a friendly unit to move, or press A after selecting one to target an attack.';
527	  }
528	
529	  if (!unit.isActiveFaction) {
530	    return 'Only the active faction can receive movement orders.';
