4	export class PathRenderer {
5	  constructor(
6	    private readonly scene: Phaser.Scene,
7	    private readonly layer: Phaser.GameObjects.Container,
8	    private readonly worldToScreen: (q: number, r: number) => { x: number; y: number },
9	  ) {}
10	
11	  render(world: WorldViewModel) {
12	    this.layer.removeAll(true);
13	
14	    for (const hex of world.overlays.reachableHexes) {
15	      const point = this.worldToScreen(hex.q, hex.r);
16	      const ring = this.scene.add.ellipse(point.x, point.y - 8, 62, 28, 0x5ec7a0, 0.28)
17	        .setStrokeStyle(3, 0xb8ffe4, 0.95);
18	      this.layer.add(ring);
19	    }
20	
21	    for (const hex of world.overlays.attackHexes) {
22	      const point = this.worldToScreen(hex.q, hex.r);
23	      const ring = this.scene.add.ellipse(point.x, point.y - 8, 62, 28, 0xb84242, 0.26)
24	        .setStrokeStyle(3, 0xffb2a7, 0.95);
25	      this.layer.add(ring);
26	    }
27	
28	    if (world.overlays.lastMove) {
29	      const point = this.worldToScreen(world.overlays.lastMove.destination.q, world.overlays.lastMove.destination.r);
30	      const marker = this.scene.add.ellipse(point.x, point.y - 8, 68, 32, 0xf2d67b, 0.08)
31	        .setStrokeStyle(3, 0xf2d67b, 0.95);
32	      this.layer.add(marker);
33	    }
34	
35	    // Render queued path before the live hover preview so the active preview stays on top.
36	    if (world.overlays.queuedPath.length >= 2) {
37	      const queuedGraphics = this.scene.add.graphics();
38	      queuedGraphics.lineStyle(4, 0x4ecdc4, 0.65);
39	      for (let index = 0; index < world.overlays.queuedPath.length - 1; index += 1) {
40	        const current = world.overlays.queuedPath[index];
41	        const next = world.overlays.queuedPath[index + 1];
42	        const from = this.worldToScreen(current.q, current.r);
43	        const to = this.worldToScreen(next.q, next.r);
44	        this.drawDashedLine(queuedGraphics, from.x, from.y - 8, to.x, to.y - 8, 8, 5);
45	      }
46	      this.layer.add(queuedGraphics);
47	
48	      for (const node of world.overlays.queuedPath) {
49	        const point = this.worldToScreen(node.q, node.r);
50	        const isLast = node.step === world.overlays.queuedPath.length - 1;
51	        const marker = this.scene.add.ellipse(
52	          point.x,
53	          point.y - 8,
54	          isLast ? 16 : 10,
55	          isLast ? 8 : 5,
56	          0x4ecdc4,
57	          0.5,
58	        ).setStrokeStyle(2, 0x7eeee4, 0.85);
59	        this.layer.add(marker);
60	      }
61	    }
62	
63	    if (world.overlays.pathPreview.length < 2) {
64	      return;
65	    }
66	
67	    const graphics = this.scene.add.graphics();
68	    graphics.lineStyle(6, 0xf2d67b, 0.92);
69	    for (let index = 0; index < world.overlays.pathPreview.length - 1; index += 1) {
70	      const current = world.overlays.pathPreview[index];
71	      const next = world.overlays.pathPreview[index + 1];
72	      const from = this.worldToScreen(current.q, current.r);
73	      const to = this.worldToScreen(next.q, next.r);
74	      graphics.lineBetween(from.x, from.y - 8, to.x, to.y - 8);
75	    }
76	    this.layer.add(graphics);
77	
78	    for (const node of world.overlays.pathPreview) {
79	      const point = this.worldToScreen(node.q, node.r);
80	      const marker = this.scene.add.ellipse(point.x, point.y - 8, node.step === 0 ? 18 : 14, node.step === 0 ? 10 : 8, 0xf7e7a8, node.step === 0 ? 0.78 : 0.9)
81	        .setStrokeStyle(2, 0xfff4c8, 0.95);
82	      this.layer.add(marker);
83	    }
84	  }
85	
86	  private drawDashedLine(
87	    graphics: Phaser.GameObjects.Graphics,
88	    x1: number,
89	    y1: number,
90	    x2: number,
91	    y2: number,
92	    dashLength: number,
93	    gapLength: number,
94	  ) {
95	    const dx = x2 - x1;
96	    const dy = y2 - y1;
97	    const distance = Math.sqrt(dx * dx + dy * dy);
98	    if (distance === 0) {
99	      return;
100	    }
101	
102	    const stepX = dx / distance;
103	    const stepY = dy / distance;
104	
105	    let position = 0;
106	    let drawing = true;
107	    while (position < distance) {
108	      const segmentLength = drawing
109	        ? Math.min(dashLength, distance - position)
110	        : Math.min(gapLength, distance - position);
111	      if (drawing) {
112	        const startX = x1 + stepX * position;
113	        const startY = y1 + stepY * position;
114	        const endX = x1 + stepX * (position + segmentLength);
115	        const endY = y1 + stepY * (position + segmentLength);
116	        graphics.lineBetween(startX, startY, endX, endY);
117	      }
118	      position += segmentLength;
119	      drawing = !drawing;
120	    }
121	  }
122	}

