281	  /** Find the player's starting position: home city of active faction, or any active-faction unit */
282	  private findPlayerStart(state: ClientState): { q: number; r: number } {
283	    // Prefer the active faction's home city
284	    const activeFaction = state.world.factions.find((f) => f.id === state.world.activeFactionId);
285	    if (activeFaction?.homeCityId) {
286	      const homeCity = state.world.cities.find((c) => c.id === activeFaction.homeCityId);
287	      if (homeCity) return { q: homeCity.q, r: homeCity.r };
288	    }
289	
290	    // Fall back to any city owned by the active faction
291	    const factionCity = state.world.cities.find(
292	      (c) => c.factionId === state.world.activeFactionId && c.visible,
293	    );
294	    if (factionCity) return { q: factionCity.q, r: factionCity.r };
295	
296	    // Fall back to any visible unit belonging to the active faction
297	    const activeUnit = state.world.units.find(
298	      (u) => u.isActiveFaction && u.visible,
299	    );

300	    if (activeUnit) return { q: activeUnit.q, r: activeUnit.r };
301	
302	    // Last resort: map center
303	    return { q: 0, r: 0 };
304	  }
