210	  private handleHexClick(state: ClientState, q: number, r: number, pointer?: Phaser.Input.Pointer) {
211	    if (this.combatAnimator.isAnimating()) return;
212	    // Right-click is handled by handleRightClick — ignore here to avoid eating the selection
213	    if (MapScene.isRightClick(pointer)) return;
214	
215	    const key = `${q},${r}`;
216	    const selectedUnitId = state.actions.selectedUnitId;
217	    const attackTarget = state.actions.attackTargets.find((target) => target.key === key) ?? null;
218	    const clickedUnit = state.world.units.find((unit) => unit.q === q && unit.r === r);
219	
220	    // Double-click on hex with a unit in a city → open city production popup
221	    if (clickedUnit && this.isDoubleClick(key)) {
222	      const city = this.findCityAtHex(state, q, r);
223	      if (city) {
224	        this.controller.dispatch({ type: 'select_city', cityId: city.id });
225	        return;
226	      }
227	    }
228	
229	    // Left-click on own unit → focus (select for movement, no UI popout)
230	    if (state.mode === 'play' && clickedUnit?.isActiveFaction) {
231	      this.controller.dispatch({ type: 'focus_unit', unitId: clickedUnit.id });
232	      return;
233	    }
234	
235	    if (state.mode === 'play' && selectedUnitId && state.actions.targetingMode === 'attack' && attackTarget) {
236	      this.controller.dispatch({
237	        type: 'attack_unit',
238	        attackerId: selectedUnitId,
239	        defenderId: attackTarget.unitId,
240	      });
241	      return;
242	    }
243	
244	    // Left-click beyond reachable range → queue multi-turn move (on visible/explored terrain)
245	    if (state.mode === 'play' && selectedUnitId) {
246	      const legalMove = state.actions.legalMoves.find((hex) => hex.key === key);
247	      if (!legalMove) {
248	        const clickedHex = state.world.map.hexes.find((h) => h.key === key);
249	        if (clickedHex && (clickedHex.visibility === 'visible' || clickedHex.visibility === 'explored')) {
250	          this.controller.dispatch({
251	            type: 'queue_move',
252	            unitId: selectedUnitId,
253	            destination: { q, r },
254	          });
255	          return;
256	        }
257	      }
258	    }
259	
260	    // Clicking empty terrain deselects — collapses the sidebar
261	    this.controller.dispatch({ type: 'select_hex', q: -1, r: -1 });
262	  }
