468	  private screenToWorld(x: number, y: number) {
469	    const q = Math.round(((x / TILE_HALF_WIDTH) + (y / TILE_HALF_HEIGHT)) / 2);
470	    const r = Math.round(((y / TILE_HALF_HEIGHT) - (x / TILE_HALF_WIDTH)) / 2);
471	    return Number.isFinite(q) && Number.isFinite(r) ? { q, r } : null;
472	  }
