264	  private layoutCamera(state: ClientState) {
265	    const points = state.world.map.hexes.map((hex) => this.worldToScreen(hex.q, hex.r));
266	    const minX = Math.min(...points.map((point) => point.x - 96));
267	    const maxX = Math.max(...points.map((point) => point.x + 96));
268	    const minY = Math.min(...points.map((point) => point.y - 96));
269	    const maxY = Math.max(...points.map((point) => point.y + 96));
270	
271	    this.cameras.main.setBounds(minX, minY, maxX - minX, maxY - minY);
272	    if (!this.cameraInitialized) {
273	      const startPos = this.findPlayerStart(state);
274	      const screenPos = this.worldToScreen(startPos.q, startPos.r);
275	      this.cameras.main.centerOn(screenPos.x, screenPos.y);
276	      this.cameraInitialized = true;
277	    }
278	    this.cameras.main.setZoom(state.camera.zoom);
279	  }
