5	export interface StrategicTargetScoreInput {
6	  isFocusTarget: boolean;
7	  isAdjacentToPrimaryObjectiveCity: boolean;
8	  isRouted: boolean;
9	  hpRatio: number;
10	  attacksFromThreatenedCityHex: boolean;
11	  finishOffPriorityTarget: boolean;
12	  isolatedFromAnchor: boolean;
13	}
14	
15	export interface AttackCandidateScoreInput {
16	  roleEffectiveness: number;
17	  weaponEffectiveness: number;
18	  reverseRoleEffectiveness: number;
19	  targetHpRatio: number;
20	  targetRouted: boolean;
21	  strategicTargetScore: number;
22	  extraScore?: number;
23	  distancePenalty?: number;
24	  isSiegeVsCity?: boolean;
25	  isSiegeVsFort?: boolean;
26	}
27	
28	export interface MoveCandidateScoreInput {
29	  assignment: UnitAssignment;
30	  originWaypointDistance: number;
31	  waypointDistance: number;
32	  terrainScore: number;
33	  supportScore: number;
34	  originSupport: number;
35	  originAnchorDistance: number;
36	  anchorDistance: number;
37	  cityDistance: number;
38	  hiddenExplorationBonus?: boolean;
39	  unsafeAfterMove?: boolean;
40	}
41	
42	export interface RetreatRiskInput {
43	  hpRatio: number;
44	  nearbyEnemies: number;
45	  nearbyFriendlies: number;
46	  nearestFriendlyDistance: number;
47	  anchorDistance: number;
48	}
49	
50	export interface EngageTargetGateInput {
51	  attackScore: number;
52	  retreatRisk: number;
53	}
54	
55	export function scoreStrategicTarget(input: StrategicTargetScoreInput): number {
56	  let score = 0;
57	  if (input.isFocusTarget) score += 6;
58	  if (input.isAdjacentToPrimaryObjectiveCity) score += 4;
59	  if (input.isRouted) score += 2;
60	  if (input.hpRatio <= 0.4) score += 3;
61	  if (input.attacksFromThreatenedCityHex) score += 4;
62	  if (input.finishOffPriorityTarget) score += 3;
63	  if (input.isolatedFromAnchor) score -= 6;
64	  return score;
65	}
66	
67	export function scoreAttackCandidate(input: AttackCandidateScoreInput): number {
68	  let score = 0;
69	  score += input.roleEffectiveness * 10;
70	  score += input.weaponEffectiveness * 10;
71	  score += (1 - input.targetHpRatio) * 5;
72	  if (input.targetRouted) score += 8;
73	  score -= input.reverseRoleEffectiveness * 5;
74	  score += input.strategicTargetScore;
75	  score += input.extraScore ?? 0;
76	  score -= input.distancePenalty ?? 0;
77	  if (input.isSiegeVsCity) score += 12;
78	  if (input.isSiegeVsFort) score += 6;
79	  return score;
80	}
81	
82	export function scoreMoveCandidate(input: MoveCandidateScoreInput): number {
83	  let score = (input.originWaypointDistance - input.waypointDistance) * 8;
84	  score += input.terrainScore * 1.5;
85	  score += input.supportScore - input.originSupport;
86	
87	  if (input.assignment === 'defender' || input.assignment === 'recovery') {
88	    score += Math.max(0, input.originAnchorDistance - input.anchorDistance) * 3;
89	    score += Math.max(0, 4 - input.cityDistance) * 1.5;
90	  }
91	
92	  if (input.assignment === 'siege_force') {
93	    score += Math.max(0, input.originWaypointDistance - input.waypointDistance) * 2;
94	  }
95	
96	  if (input.assignment === 'reserve' && input.anchorDistance <= 2) {
97	    score += 1.5;
98	  }
99	
100	  if (input.hiddenExplorationBonus) {
101	    score += 6;
102	  }
103	
104	  if (input.unsafeAfterMove) {
105	    score -= 10;
106	  }
107	
108	  return score;
109	}
110	
111	export function computeRetreatRisk(input: RetreatRiskInput): number {
112	  const hpPressure = Math.max(0, 0.6 - input.hpRatio) * 1.25;
113	  const enemyPressure = Math.max(0, input.nearbyEnemies - input.nearbyFriendlies) * 0.12;
114	  const isolationPressure = input.nearestFriendlyDistance > 3 ? 0.2 : 0;
115	  const anchorPressure = input.anchorDistance > 4 ? 0.2 : 0;
116	  return Math.min(1.25, hpPressure + enemyPressure + isolationPressure + anchorPressure);
117	}
118	
119	export function computeAttackAdvantageFromScore(score: number): number {
120	  return 1 + score / 60;
121	}
122	
123	export function shouldEngageTarget(
124	  snapshot: AiPersonalitySnapshot | undefined,
125	  input: EngageTargetGateInput,
126	): boolean {
127	  if (!snapshot) {
128	    return input.attackScore > 0;
129	  }
130	
131	  if (shouldRetreat(snapshot, { retreatRisk: input.retreatRisk })) {
132	    return false;
133	  }
134	
135	  return shouldCommitAttack(snapshot, {
136	    attackAdvantage: computeAttackAdvantageFromScore(input.attackScore),
137	  });
138	}

1	// Territory Control System
2	// Cities claim hexes within a radius. Territory provides supply yield.
3	// Contested hexes (enemy unit inside radius) provide no yield.
4	
5	import type { GameState } from '../game/types.js';
6	import type { City } from '../features/cities/types.js';
7	import type { HexCoord, FactionId, CityId, UnitId } from '../types.js';
8	import { getHexesInRange, hexDistance, hexToKey, keyToHex } from '../core/grid.js';
9	import { isUnitVisibleTo } from './fogSystem.js';
10	
11	const TERRITORY_SUPPLY_PER_HEX = 0.1;
12	
13	/**
14	 * Get all hex keys claimed by a city's territory radius.
15	 */
16	export function getCityTerritoryHexes(
17	  city: City,
18	  map: { tiles: Map<string, any> },
19	  radius: number = 2
20	): Set<string> {
21	  const hexes = getHexesInRange(city.position, radius);
22	  const onMap = new Set<string>();
23	  for (const hex of hexes) {
24	    const key = hexToKey(hex);
25	    if (map.tiles.has(key)) {
26	      onMap.add(key);
27	    }
28	  }
29	  return onMap;
30	}
31	
32	/**
33	 * Check if a hex is contested by an enemy unit within territory range.
34	 * A hex is contested if any enemy unit is within `radius` of the claiming city
35	 * AND the hex is within that city's territory.
36	 */
37	export function isHexContested(
38	  hex: HexCoord,
39	  claimingFactionId: FactionId,
40	  state: GameState
41	): boolean {
42	  for (const [, unit] of state.units) {
43	    if (unit.factionId !== claimingFactionId && unit.hp > 0 && isUnitVisibleTo(state, claimingFactionId, unit)) {
44	      const dist = hexDistance(unit.position, hex);
45	      if (dist <= 1) {
46	        return true;
47	      }
48	    }
49	  }
50	  return false;
51	}
52	
53	/**
54	 * Get the faction that owns a hex (closest city claims it).
55	 * Returns null if unclaimed or contested.
56	 */
57	export function getHexOwner(
58	  hex: HexCoord,
59	  state: GameState
60	): FactionId | null {
61	  let closestCity: { city: City; dist: number } | null = null;
62	
63	  for (const [, city] of state.cities) {
64	    const dist = hexDistance(city.position, hex);
65	    if (dist <= (city.territoryRadius ?? 2)) {
66	      if (!closestCity || dist < closestCity.dist) {
67	        closestCity = { city, dist };
68	      }
69	    }
70	  }
71	
72	  if (!closestCity) return null;
73	
74	  // Check if any enemy unit is adjacent to this hex (contested)
75	  if (isHexContested(hex, closestCity.city.factionId, state)) {
76	    return null;
77	  }
78	
79	  return closestCity.city.factionId;
80	}
81	
82	/**
83	 * Calculate total territory supply yield for a faction.
84	 * Each uncontested territory hex provides TERRITORY_SUPPLY_PER_HEX supply.
85	 */
86	export function calculateTerritoryYield(
87	  factionId: FactionId,
88	  state: GameState
89	): number {
90	  let totalYield = 0;
91	  const countedHexes = new Set<string>();
92	
93	  for (const [, city] of state.cities) {
94	    if (city.factionId !== factionId) continue;
95	
96	    // Skip besieged or vulnerable cities (siege system)
97	    if (city.besieged) continue;
98	
99	    const radius = city.territoryRadius ?? 2;
100	    const territory = getCityTerritoryHexes(city, state.map!, radius);
101	
102	    for (const hexKey of territory) {
103	      if (countedHexes.has(hexKey)) continue;
104	      countedHexes.add(hexKey);
105	
106	      const hex = keyToHex(hexKey);
107	      const owner = getHexOwner(hex, state);
108	      if (owner === factionId) {
109	        totalYield += TERRITORY_SUPPLY_PER_HEX;
110	      }
111	    }
112	  }
113	
114	  return Number(totalYield.toFixed(2));
115	}
116	
117	const ENCIRCLEMENT_THRESHOLD = 3;
118	const ENCIRCLEMENT_RADIUS = 2;
119	
120	/**
121	 * Check if a city is encircled (enough enemy units nearby).
122	 * Uses proximity-based check: counts enemy units within ENCIRCLEMENT_RADIUS.
123	 * Used by the siege system.
124	 */
125	export function isCityEncircled(
126	  city: City,
127	  state: GameState
128	): boolean {
129	  let enemyCount = 0;
130	  for (const [, unit] of state.units) {
131	    if (unit.factionId === city.factionId || unit.hp <= 0) continue;
132	    const dist = hexDistance(unit.position, city.position);
133	    if (dist <= ENCIRCLEMENT_RADIUS && dist > 0) {
134	      enemyCount++;
135	    }
136	  }
137	
138	  return enemyCount >= ENCIRCLEMENT_THRESHOLD;
139	}
140	
141	/**
142	 * Check if encirclement is broken (enemy count drops below threshold within radius).
143	 */
144	export function isEncirclementBroken(
145	  city: City,
146	  state: GameState
147	): boolean {
148	  let enemyCount = 0;
149	  for (const [, unit] of state.units) {
150	    if (unit.factionId === city.factionId || unit.hp <= 0) continue;
151	    const dist = hexDistance(unit.position, city.position);
152	    if (dist <= ENCIRCLEMENT_RADIUS && dist > 0) {
153	      enemyCount++;
154	    }
155	  }
156	
157	  return enemyCount < ENCIRCLEMENT_THRESHOLD;
158	}
159	
160	// Local helper to avoid importing occupancySystem (circular risk)
161	function getUnitAtHexFromState(state: GameState, hex: HexCoord): UnitId | undefined {
162	  for (const [unitId, unit] of state.units) {
163	    if (unit.position.q === hex.q && unit.position.r === hex.r) {
164	      return unitId;
165	    }
166	  }
167	  return undefined;
168	}

