99	export function computeFactionStrategy(
100	  state: GameState,
101	  factionId: FactionId,
102	  registry: RulesRegistry,
103	  difficulty?: DifficultyLevel,
104	): FactionStrategy {
105	  const difficultyProfile = getAiDifficultyProfile(difficulty);
106	  const previousStrategy = state.factionStrategies.get(factionId);
107	  const faction = state.factions.get(factionId);
108	  if (!faction) {
109	    return createEmptyStrategy(state.round, factionId);
110	  }
111	
112	  const friendlyUnits = getLivingUnitsForFaction(state, factionId);
113	  const enemyUnits = getLivingEnemyUnits(state, factionId, difficultyProfile);
114	  const threatenedCities = assessThreatenedCities(state, factionId, difficultyProfile);
115	  const fronts = detectFronts(state, factionId, threatenedCities, difficultyProfile);
116	  const personality = computeAiPersonalitySnapshot(state, factionId, registry, difficulty);
117	  const economy = state.economy.get(factionId);
118	  const supplyDeficit = economy ? getSupplyDeficit(economy) : 0;
119	  const exhaustion = state.warExhaustion.get(factionId)?.exhaustionPoints ?? 0;
120	  const postureDecision = determinePosture(
121	    friendlyUnits.length,
122	    enemyUnits.length,
123	    threatenedCities,
124	    exhaustion,
125	    supplyDeficit,
126	    fronts,
127	    personality,
128	    state.round,
129	    difficultyProfile,
130	    previousStrategy,
131	  );
132	  const posture = postureDecision.posture;
133	  const primaryEnemyFactionId = choosePrimaryEnemyFaction(fronts, enemyUnits);
134	  const primaryCityObjectiveId = choosePrimaryCityObjective(
135	    fronts,
136	    threatenedCities,
137	    posture,
138	    state,
139	    factionId,
140	    difficultyProfile,
141	  );
142	  const primaryFrontAnchor = choosePrimaryFrontAnchor(fronts, threatenedCities, posture);
143	  const focusTargetDecision = chooseFocusTargets(
144	    state,
145	    factionId,
146	    primaryCityObjectiveId,
147	    fronts,
148	    posture,
149	    personality,
150	    difficultyProfile,
151	  );
152	  const focusTargetUnitIds = focusTargetDecision.unitIds;
153	  const regroupAnchors = buildRegroupAnchors(state, factionId, fronts, threatenedCities);
154	  const retreatAnchors = getFriendlyCityAnchors(state, factionId);
155	  const hybridGoal = buildHybridGoal(state, factionId, registry);
156	  const absorptionGoal = buildAbsorptionGoal(state, factionId, enemyUnits, primaryEnemyFactionId);
157	  const assignmentDecision = assignUnitIntents(
158	    state,
159	    factionId,
160	    friendlyUnits,
161	    posture,
162	    personality,
163	    threatenedCities,
164	    primaryCityObjectiveId,
165	    primaryFrontAnchor,
166	    focusTargetDecision.candidates,
167	    regroupAnchors,
168	    retreatAnchors,
169	    difficultyProfile,
170	    previousStrategy,
171	  );
172	  const debugReasons = buildDebugReasons(
173	    posture,
174	    threatenedCities,
175	    fronts,
176	    supplyDeficit,
177	    exhaustion,
178	    hybridGoal,
179	    absorptionGoal,
180	    postureDecision.reasons,
181	    focusTargetDecision.reasons,
182	    assignmentDecision.reasons,
183	  );
184	
185	  return {
186	    factionId,
187	    round: state.round,
188	    personality,
189	    posture,
190	    primaryEnemyFactionId,
191	    primaryObjective: summarizePrimaryObjective(posture, threatenedCities, primaryCityObjectiveId, primaryEnemyFactionId),
192	    primaryCityObjectiveId,
193	    primaryFrontAnchor,
194	    threatenedCities,
195	    fronts,
196	    focusTargetUnitIds,
197	    regroupAnchors,
198	    retreatAnchors,
199	    unitIntents: assignmentDecision.intents,
200	    productionPriorities: [],
201	    researchPriorities: [],
202	    hybridGoal,
203	    absorptionGoal,
204	    debugReasons,
205	  };
206	}
