260	function assessThreatenedCities(
261	  state: GameState,
262	  factionId: FactionId,
263	  difficultyProfile: AiDifficultyProfile,
264	): ThreatAssessment[] {
265	  return Array.from(state.cities.values())
266	    .filter((city) => city.factionId === factionId)
267	    .map((city) => {
268	      let nearbyEnemyUnits = 0;
269	      let nearbyFriendlyUnits = 0;
270	      let nearestEnemyFactionId: FactionId | undefined;
271	      let nearestEnemyDistance = Infinity;
272	
273	      for (const unit of state.units.values()) {
274	        if (unit.hp <= 0) continue;
275	        if (unit.factionId === factionId) {
276	          nearbyFriendlyUnits += 1;
277	        } else {
278	          if (!difficultyProfile.strategy.strategicFogCheat && !isUnitVisibleTo(state, factionId, unit)) continue;
279	          const dist = hexDistance(city.position, unit.position);
280	          if (dist > THREAT_RADIUS) continue;
281	          nearbyEnemyUnits += 1;
282	          if (dist < nearestEnemyDistance) {
283	            nearestEnemyDistance = dist;
284	            nearestEnemyFactionId = unit.factionId;
285	          }
286	        }
287	      }
288	
289	      const threatScore = nearbyEnemyUnits * 4 - nearbyFriendlyUnits * 2 + (city.besieged ? 6 : 0);
290	      return {
291	        cityId: city.id,
292	        threatScore,
293	        nearbyEnemyUnits,
294	        nearbyFriendlyUnits,
295	        nearestEnemyFactionId,
296	      };
297	    })
298	    .filter((threat) => threat.threatScore > 0)
299	    .sort((left, right) => {
300	      const leftCity = state.cities.get(left.cityId);
301	      const rightCity = state.cities.get(right.cityId);
302	      return right.threatScore - left.threatScore || compareHexes(leftCity?.position, rightCity?.position);
303	    });
304	}
