306	function detectFronts(
307	  state: GameState,
308	  factionId: FactionId,
309	  threatenedCities: ThreatAssessment[],
310	  difficultyProfile: AiDifficultyProfile,
311	): FrontLine[] {
312	  const fronts = new Map<string, FrontLine>();
313	  const threatenedByCity = new Map(threatenedCities.map((threat) => [threat.cityId, threat]));
314	
315	  // Helper to register a front from a known enemy position (visible or last-seen)
316	  const registerFront = (friendlyPos: HexCoord, enemyPos: HexCoord, enemyFactionId: FactionId, enemyCityId?: CityId) => {
317	    const dist = hexDistance(friendlyPos, enemyPos);
318	    if (dist > FRONT_RADIUS * 2) return; // Last-seen fronts need larger radius allowance
319	
320	    const anchor = dist <= 1
321	      ? friendlyPos
322	      : {
323	          q: Math.round((friendlyPos.q + enemyPos.q) / 2),
324	          r: Math.round((friendlyPos.r + enemyPos.r) / 2),
325	        };
326	    const key = hexToKey(anchor);
327	    const existing = fronts.get(key);
328	    const nearbyEnemyCity = enemyCityId
329	      ? state.cities.get(enemyCityId)
330	      : Array.from(state.cities.values()).find(
331	          (city) => city.factionId === enemyFactionId && hexDistance(city.position, anchor) <= THREAT_RADIUS
332	        );
333	
334	    if (!existing) {
335	      fronts.set(key, {
336	        anchor,
337	        pressure: (FRONT_RADIUS - dist + 1) * 0.5, // Last-seen fronts are weaker signals
338	        enemyFactionId,
339	        enemyCityId: nearbyEnemyCity?.id,
340	        friendlyUnits: 1,
341	        enemyUnits: 1,
342	      });
343	      return;
344	    }
345	
346	    existing.pressure += (FRONT_RADIUS - dist + 1) * 0.5;
347	    existing.friendlyUnits += 1;
348	    existing.enemyUnits += 1;
349	    if (!existing.enemyCityId && nearbyEnemyCity) {
350	      existing.enemyCityId = nearbyEnemyCity.id;
351	    }
352	  };
353	
354	  // Visible enemy units
355	  for (const friendly of state.units.values()) {
356	    if (friendly.factionId !== factionId || friendly.hp <= 0) continue;
357	    for (const enemy of state.units.values()) {
358	      if (enemy.factionId === factionId || enemy.hp <= 0) continue;
359	      if (!difficultyProfile.strategy.strategicFogCheat && !isUnitVisibleTo(state, factionId, enemy)) continue;
360	      const dist = hexDistance(friendly.position, enemy.position);
361	      if (dist > FRONT_RADIUS) continue;
362	
363	      const anchor = dist <= 1
364	        ? friendly.position
365	        : {
366	            q: Math.round((friendly.position.q + enemy.position.q) / 2),
367	            r: Math.round((friendly.position.r + enemy.position.r) / 2),
368	          };
369	      const key = hexToKey(anchor);
370	      const existing = fronts.get(key);
371	      const nearbyEnemyCity = Array.from(state.cities.values()).find(
372	        (city) => city.factionId === enemy.factionId && hexDistance(city.position, anchor) <= THREAT_RADIUS
373	      );
374	
375	      if (!existing) {
376	        fronts.set(key, {
377	          anchor,
378	          pressure: FRONT_RADIUS - dist + 1,
379	          enemyFactionId: enemy.factionId,
380	          enemyCityId: nearbyEnemyCity?.id,
381	          friendlyUnits: 1,
382	          enemyUnits: 1,
383	        });
384	        continue;
385	      }
386	
387	      existing.pressure += FRONT_RADIUS - dist + 1;
388	      existing.friendlyUnits += 1;
389	      existing.enemyUnits += 1;
390	      if (!existing.enemyCityId && nearbyEnemyCity) {
391	        existing.enemyCityId = nearbyEnemyCity.id;
392	      }
393	    }
394	  }
395	
396	  // Last-seen enemy units (memory of recently visible enemies)
397	  const lastSeenEnemies = getLastSeenEnemyUnits(state, factionId);
398	  for (const friendly of state.units.values()) {
399	    if (friendly.factionId !== factionId || friendly.hp <= 0) continue;
400	    for (const lse of lastSeenEnemies) {
401	      if (lse.roundsAgo > difficultyProfile.strategy.memoryDecayTurns) continue;
402	      registerFront(friendly.position, lse.position, lse.factionId);
403	    }
404	  }
405	
406	  for (const threat of threatenedCities) {
407	    const city = state.cities.get(threat.cityId);
408	    if (!city || !threat.nearestEnemyFactionId) continue;
409	    const key = hexToKey(city.position);
410	    const existing = fronts.get(key);
411	    if (existing) {
412	      existing.pressure += Math.max(2, threat.threatScore);
413	      continue;
414	    }
415	    fronts.set(key, {
416	      anchor: city.position,
417	      pressure: Math.max(2, threat.threatScore),
418	      enemyFactionId: threat.nearestEnemyFactionId,
419	      enemyCityId: undefined,
420	      friendlyUnits: threat.nearbyFriendlyUnits,
421	      enemyUnits: threat.nearbyEnemyUnits,
422	    });
423	  }
424	
425	  return Array.from(fronts.values()).sort(
426	    (left, right) => right.pressure - left.pressure || hexToKey(left.anchor).localeCompare(hexToKey(right.anchor))
427	  );
428	}
