430	function determinePosture(
431	  unitCount: number,
432	  enemyUnitCount: number,
433	  threatenedCities: ThreatAssessment[],
434	  exhaustion: number,
435	  supplyDeficit: number,
436	  fronts: FrontLine[],
437	  personality: AiPersonalitySnapshot,
438	  round: number,
439	  difficultyProfile: AiDifficultyProfile,
440	  previousStrategy: FactionStrategy | undefined,
441	): PostureDecision {
442	  const cityThreat = threatenedCities[0]?.threatScore ?? 0;
443	  const majorFront = fronts[0];
444	  if (unitCount <= 1 || exhaustion >= 10 || supplyDeficit >= 3) {
445	    return {
446	      posture: 'recovery',
447	      reasons: ['posture_guard=recovery:critical_recovery_state'],
448	    };
449	  }
450	  if (cityThreat >= 5) {
451	    return {
452	      posture: 'defensive',
453	      reasons: ['posture_guard=defensive:high_city_threat'],
454	    };
455	  }
456	  const context = {
457	    threatenedCities: threatenedCities.length,
458	    fronts: fronts.length,
459	    localAdvantage: unitCount - enemyUnitCount,
460	    supplyDeficit,
461	    exhaustion,
462	  };
463	  const scoreByPosture = new Map<FactionPosture, number>();
464	  for (const posture of ['offensive', 'balanced', 'defensive', 'recovery', 'siege', 'exploration'] as FactionPosture[]) {
465	    scoreByPosture.set(posture, scorePosture(personality, context, posture));
466	  }
467	  if (majorFront && majorFront.enemyCityId && majorFront.friendlyUnits >= majorFront.enemyUnits + 1) {
468	    scoreByPosture.set('siege', (scoreByPosture.get('siege') ?? 0) + 2.5);
469	  }
470	  if (enemyUnitCount > 0 && unitCount >= enemyUnitCount * 2 && unitCount >= 5) {
471	    scoreByPosture.set('siege', (scoreByPosture.get('siege') ?? 0) + 2);
472	  }
473	  if (majorFront && majorFront.friendlyUnits >= majorFront.enemyUnits) {
474	    scoreByPosture.set('offensive', (scoreByPosture.get('offensive') ?? 0) + 1.5);
475	  }
476	  if (fronts.length === 0 && threatenedCities.length === 0) {
477	    scoreByPosture.set('exploration', (scoreByPosture.get('exploration') ?? 0) + 2.5);
478	  }
479	  if (enemyUnitCount === 0) {
480	    scoreByPosture.set('offensive', (scoreByPosture.get('offensive') ?? 0) - 2);
481	    scoreByPosture.set('siege', (scoreByPosture.get('siege') ?? 0) - 2);
482	  }
483	  if (round >= difficultyProfile.strategy.postureExplorationDeadline) {
484	    scoreByPosture.set('exploration', Number.NEGATIVE_INFINITY);
485	  }
486	  if (enemyUnitCount > 0 && unitCount >= enemyUnitCount + 2) {
487	    scoreByPosture.set('balanced', (scoreByPosture.get('balanced') ?? 0) - 2.5);
488	    scoreByPosture.set('offensive', (scoreByPosture.get('offensive') ?? 0) + 1.5);
489	  }
490	  if (previousStrategy && difficultyProfile.strategy.postureCommitmentLockTurns > 0) {
491	    const roundsSinceLast = round - previousStrategy.round;
492	    const previousUnitCount = Object.keys(previousStrategy.unitIntents).length;
493	    const lostArmyMass =
494	      previousUnitCount > 0 && unitCount <= Math.max(1, Math.floor(previousUnitCount * 0.7));
495	    const decisiveBreak = cityThreat >= 5 || exhaustion >= 8 || supplyDeficit >= 2 || lostArmyMass;
496	    const stickyPosture =
497	      previousStrategy.posture === 'offensive' || previousStrategy.posture === 'siege'
498	        ? previousStrategy.posture
499	        : undefined;
500	    if (
501	      stickyPosture
502	      && roundsSinceLast <= difficultyProfile.strategy.postureCommitmentLockTurns
503	      && !decisiveBreak
504	    ) {
505	      scoreByPosture.set(stickyPosture, (scoreByPosture.get(stickyPosture) ?? 0) + 6);
506	    }
507	  }
508	  const ranked = Array.from(scoreByPosture.entries()).sort(
509	    (left, right) => right[1] - left[1] || left[0].localeCompare(right[0]),
510	  );
511	  const winner = ranked[0];
512	  const runnerUp = ranked[1];
513	  return {
514	    posture: winner[0],
515	    reasons: [
516	      `posture_choice=${winner[0]}:${winner[1].toFixed(2)}`,
517	      runnerUp ? `posture_runner_up=${runnerUp[0]}:${runnerUp[1].toFixed(2)}` : 'posture_runner_up=none',
518	    ],
519	  };
520	}
521	function choosePrimaryEnemyFaction(fronts: FrontLine[], enemyUnits: UnitWithPrototype[]): FactionId | undefined {
522	  if (fronts.length > 0) {
523	    return fronts[0].enemyFactionId;
524	  }
525	  return enemyUnits[0]?.unit.factionId;
526	}
