528	function choosePrimaryCityObjective(
529	  fronts: FrontLine[],
530	  threatenedCities: ThreatAssessment[],
531	  posture: FactionPosture,
532	  state?: GameState,
533	  factionId?: FactionId,
534	  difficultyProfile?: AiDifficultyProfile,
535	): CityId | undefined {
536	  if ((posture === 'defensive' || posture === 'recovery') && threatenedCities[0]) {
537	    return threatenedCities[0].cityId;
538	  }
539	
540	  // Pirate Lords: prefer coastal enemy cities as offensive objectives
541	  const coastalFront = fronts.find((front) => {
542	    if (!front.enemyCityId || !state || !factionId) return false;
543	    const city = state.cities.get(front.enemyCityId);
544	    if (!city) return false;
545	    const terrain = state.map?.tiles.get(hexToKey(city.position))?.terrain ?? '';
546	    return terrain === 'coast' || terrain === 'river';
547	  });
548	
549	  if (coastalFront?.enemyCityId) {
550	    return coastalFront.enemyCityId;
551	  }
552	
553	  const frontCity = fronts.find((front) => Boolean(front.enemyCityId))?.enemyCityId;
554	  if (frontCity) return frontCity;
555	
556	  if (state && factionId && difficultyProfile?.strategy.strategicFogCheat) {
557	    const homeCityId = state.factions.get(factionId)?.homeCityId;
558	    const homeCity = homeCityId ? state.cities.get(homeCityId) : undefined;
559	    const strategicCity = Array.from(state.cities.values())
560	      .filter((city) => city.factionId !== factionId)
561	      .sort((left, right) => {
562	        const leftDistance = hexDistance(left.position, homeCity?.position ?? left.position);
563	        const rightDistance = hexDistance(right.position, homeCity?.position ?? right.position);
564	        return leftDistance - rightDistance || left.id.localeCompare(right.id);
565	      })[0];
566	    if (strategicCity) {
567	      return strategicCity.id;
568	    }
569	  }
570	
571	  if (state && factionId && posture !== 'defensive' && posture !== 'recovery') {
572	    const lastSeenCities = getLastSeenEnemyCities(state, factionId)
573	      .filter((c) => c.roundsAgo <= (difficultyProfile?.strategy.memoryDecayTurns ?? 20))
574	      .sort((a, b) => a.roundsAgo - b.roundsAgo);
575	
576	    if (lastSeenCities.length > 0) {
577	      return lastSeenCities[0].cityId as CityId;
578	    }
579	  }
580	
581	  return undefined;
582	}
