584	function choosePrimaryFrontAnchor(
585	  fronts: FrontLine[],
586	  threatenedCities: ThreatAssessment[],
587	  posture: FactionPosture
588	): HexCoord | undefined {
589	  if ((posture === 'defensive' || posture === 'recovery') && threatenedCities.length > 0) {
590	    return fronts[0]?.anchor;
591	  }
592	  return fronts[0]?.anchor;
593	}
