595	function chooseFocusTargets(
596	  state: GameState,
597	  factionId: FactionId,
598	  primaryCityObjectiveId: CityId | undefined,
599	  fronts: FrontLine[],
600	  posture: FactionPosture,
601	  personality: AiPersonalitySnapshot,
602	  difficultyProfile: AiDifficultyProfile,
603	): FocusTargetDecision {
604	  const targetEnemyFactionId = fronts[0]?.enemyFactionId;
605	  const candidateEnemyUnits = getLivingEnemyUnits(state, factionId, difficultyProfile);
606	  const primaryCityPosition = primaryCityObjectiveId
607	    ? state.cities.get(primaryCityObjectiveId)?.position
608	    : undefined;
609	  const candidates = candidateEnemyUnits
610	    .map((entry) => {
611	      const targetPrototype = state.prototypes.get(entry.unit.prototypeId);
612	      const cityDistance = primaryCityPosition
613	        ? hexDistance(entry.unit.position, primaryCityPosition)
614	        : 99;
615	      const hpRatio = entry.unit.hp / Math.max(1, entry.unit.maxHp);
616	      const routedBonus = entry.unit.routed ? 3 : 0;
617	      const sameFrontBonus = targetEnemyFactionId && entry.unit.factionId === targetEnemyFactionId ? 2 : 0;
618	      const postureBonus = posture === 'recovery' ? (entry.unit.routed ? 2 : 0) : 1;
619	      const nearestEnemySupport = nearestEnemySupportDistance(state, entry.unit);
620	      const isolated = nearestEnemySupport > 2;
621	      const capturable = entry.unit.routed || hpRatio <= 0.35;
622	      const wounded = hpRatio <= 0.6;
623	      const terrainId = state.map?.tiles.get(hexToKey(entry.unit.position))?.terrain;
624	      const antiSkirmishScore = isSkirmisherPrototype(targetPrototype)
625	        ? difficultyProfile.personality.antiSkirmishResponseWeight
626	        : 0;
627	      const personalityScore = scoreFocusTarget(
628	        personality,
629	        { targetDistance: cityDistance },
630	        {
631	          isolated,
632	          capturable,
633	          wounded,
634	          isCity: false,
635	          terrainId,
636	        },
637	      );
638	      const baseScore =
639	        sameFrontBonus + routedBonus + postureBonus + antiSkirmishScore + (1 - hpRatio) * 4 - cityDistance * 0.25;
640	      return {
641	        unitId: entry.unit.id,
642	        score: baseScore + personalityScore,
643	        baseScore,
644	        personalityScore,
645	      };
646	    })
647	    .sort((left, right) => {
