210	    const responsePressure = Math.min(
211	      3,
212	      visibleEnemySkirmishers * profile.personality.antiSkirmishResponseWeight * 0.25,
213	    );
214	    snapshot.assignmentWeights.defender = (snapshot.assignmentWeights.defender ?? 0) + responsePressure;
215	    snapshot.assignmentWeights.reserve = (snapshot.assignmentWeights.reserve ?? 0) + responsePressure * 0.8;
216	    snapshot.productionWeights.ranged = (snapshot.productionWeights.ranged ?? 0) + responsePressure * 0.7;
217	    snapshot.productionWeights.melee = (snapshot.productionWeights.melee ?? 0) + responsePressure * 0.4;
218	    snapshot.reasons.push(`state: skirmisher_pressure=${visibleEnemySkirmishers}`);
219	  }
220	
221	  const friendlyUnits = Array.from(state.units.values()).filter((unit) => unit.hp > 0 && unit.factionId === factionId).length;
222	  const visibleEnemies = Array.from(state.units.values()).filter((unit) => unit.hp > 0 && unit.factionId !== factionId).length;
223	  if (friendlyUnits >= visibleEnemies + 2 && visibleEnemies > 0) {
224	    snapshot.scalars.aggression = clampScalar(snapshot.scalars.aggression + 0.1);
225	    snapshot.scalars.siegeBias = clampScalar(snapshot.scalars.siegeBias + 0.1);
226	    snapshot.reasons.push('state: local_superiority');
227	  } else if (friendlyUnits <= Math.max(1, visibleEnemies - 1)) {
228	    snapshot.scalars.cohesion = clampScalar(snapshot.scalars.cohesion + 0.1);
229	    snapshot.assignmentWeights.reserve = (snapshot.assignmentWeights.reserve ?? 0) + 1;
230	    snapshot.reasons.push('state: strategic_pressure');
231	  }
232	
233	  snapshot.thresholds.commitAdvantage = clamp(snapshot.thresholds.commitAdvantage, 0.85, 1.75);
234	  snapshot.thresholds.retreatThreshold = clamp(snapshot.thresholds.retreatThreshold, 0.4, 1.25);
235	  snapshot.thresholds.focusFireLimit = Math.round(clamp(snapshot.thresholds.focusFireLimit, 1, 5));
236	  snapshot.thresholds.squadSize = Math.round(clamp(snapshot.thresholds.squadSize, 1, 6));
237	}
