314	function applyDifficultyBaselineOverrides(
315	  baseline: FactionAiBaseline,
316	  difficulty?: DifficultyLevel,
317	): FactionAiBaseline {
318	  const profile = getAiDifficultyProfile(difficulty);
319	  if (!profile.adaptiveAi) {
320	    return baseline;
321	  }
322	
323	  return {
324	    ...baseline,
325	    aggression: Math.max(baseline.aggression, profile.personality.aggressionFloor),
326	    siegeBias: Math.max(baseline.siegeBias, profile.personality.siegeBiasFloor),
327	    raidBias: Math.max(baseline.raidBias, profile.personality.raidBiasFloor),
328	    focusFireLimit: baseline.focusFireLimit + profile.personality.focusFireLimitBonus,
329	    squadSize: baseline.squadSize + profile.personality.squadSizeBonus,
330	    commitAdvantage: baseline.commitAdvantage + profile.personality.commitAdvantageOffset,
331	    retreatThreshold: baseline.retreatThreshold + profile.personality.retreatThresholdOffset,
332	  };
333	}
