346	export function computeAiPersonalitySnapshot(
347	  state: GameState,
348	  factionId: FactionId,
349	  registry: RulesRegistry,
350	  difficulty?: DifficultyLevel,
351	): AiPersonalitySnapshot {
352	  const profile = getAiDifficultyProfile(difficulty);
353	  const faction = state.factions.get(factionId);
354	  const baseline = applyDifficultyBaselineOverrides(
355	    registry.getFactionAiBaseline(factionId) ?? DEFAULT_BASELINE,
356	    difficulty,
357	  );
358	  const snapshot = createBaseSnapshot(state, factionId, baseline);
359	  snapshot.reasons.push(`difficulty=${profile.difficulty}`);
360	  if (!faction) {
361	    snapshot.reasons.push('fallback: missing faction');
362	    return snapshot;
363	  }
364	
365	  const activeDoctrines = Array.from(new Set([faction.nativeDomain, ...faction.learnedDomains].filter(Boolean)));
366	  snapshot.activeDoctrines = activeDoctrines;
367	
368	  for (const doctrineId of activeDoctrines) {
369	    const doctrine = registry.getDomainAiDoctrine(doctrineId);
370	    if (!doctrine) continue;
371	    const factor = doctrineId === faction.nativeDomain ? 1 : 0.6;
372	    applyDoctrine(snapshot, doctrine, factor);
373	    snapshot.reasons.push(`${doctrineId}@${factor}`);
374	  }
375	
376	  applyStateModifiers(snapshot, state, factionId, difficulty);
377	  return snapshot;
378	}
