380	export function scorePosture(
381	  snapshot: AiPersonalitySnapshot,
382	  context: AiDecisionContext,
383	  posture: FactionPosture,
384	): number {
385	  const threatenedCities = context.threatenedCities ?? 0;
386	  const fronts = context.fronts ?? 0;
387	  const localAdvantage = context.localAdvantage ?? 0;
388	  const supplyDeficit = context.supplyDeficit ?? 0;
389	
390	  switch (posture) {
391	    case 'offensive':
392	      return snapshot.scalars.aggression * 4 + snapshot.scalars.mobilityBias * 2 + localAdvantage - supplyDeficit;
393	    case 'defensive':
394	      return snapshot.scalars.defenseBias * 4 + threatenedCities * 2 + snapshot.scalars.caution * 2;
395	    case 'recovery':
396	      return snapshot.scalars.caution * 3 + snapshot.scalars.attritionBias * 2 + supplyDeficit * 1.5;
397	    case 'siege':
398	      return snapshot.scalars.siegeBias * 4 + localAdvantage * 1.5 - threatenedCities;
399	    case 'exploration':
400	      return snapshot.scalars.exploreBias * 4 + snapshot.scalars.mobilityBias * 2 - fronts;
401	    case 'balanced':
402	    default:
403	      return snapshot.scalars.cohesion * 3 + snapshot.scalars.opportunism * 1.5;
404	  }
405	}
