407	export function scoreFocusTarget(
408	  snapshot: AiPersonalitySnapshot,
409	  context: AiDecisionContext,
410	  target: { isolated?: boolean; capturable?: boolean; wounded?: boolean; isCity?: boolean; terrainId?: string },
411	): number {
