414	  if (target.capturable) score += snapshot.targetWeights.capturable ?? 0;
415	  if (target.wounded) score += snapshot.targetWeights.wounded ?? 0;
416	  if (target.isCity) score += snapshot.targetWeights.city ?? 0;
417	  if (target.terrainId) score += snapshot.terrainScores[target.terrainId] ?? 0;
418	  score -= (context.targetDistance ?? 0) * 0.1;
419	  return score;
