422	export function scoreProductionCandidate(
423	  snapshot: AiPersonalitySnapshot,
424	  context: AiDecisionContext,
425	  prototype: { role?: string; tags?: string[]; supplyCost?: number; productionCost?: number },
426	): number {
427	  const roleScore = prototype.role ? (snapshot.productionWeights[prototype.role] ?? 0) : 0;
428	  const navalScore = prototype.tags?.includes('naval') ? (snapshot.productionWeights.naval ?? 0) : 0;
429	  const siegeScore = prototype.tags?.includes('siege') ? (snapshot.productionWeights.siege ?? 0) : 0;
430	  const supplyPenalty = (prototype.supplyCost ?? 0) * Math.max(0, context.supplyDeficit ?? 0);
431	  const productionPenalty = (prototype.productionCost ?? 0) * 0.1;
432	  return roleScore + navalScore + siegeScore - supplyPenalty - productionPenalty;
433	}
