111	export function computeRetreatRisk(input: RetreatRiskInput): number {
112	  const hpPressure = Math.max(0, 0.6 - input.hpRatio) * 1.25;
113	  const enemyPressure = Math.max(0, input.nearbyEnemies - input.nearbyFriendlies) * 0.12;
114	  const isolationPressure = input.nearestFriendlyDistance > 3 ? 0.2 : 0;
115	  const anchorPressure = input.anchorDistance > 4 ? 0.2 : 0;
116	  return Math.min(1.25, hpPressure + enemyPressure + isolationPressure + anchorPressure);
117	}
