41	export function buildCombatAnimationScript(
42	  outcome: CombatAnimationOutcome,
43	  attacker: UnitView,
44	  defender: UnitView,
45	): CombatAnimationScript {
46	  const attackerEndHp = Math.max(0, attacker.hp - outcome.attackerDamage);
47	  const defenderEndHp = Math.max(0, defender.hp - outcome.defenderDamage);
48	
49	  const attackerHits = splitDamageIntoHits(
50	    outcome.defenderDamage,
51	    pickHitCount(outcome.defenderDamage, defender.maxHp, false),
52	    true,
53	  );
54	  const defenderHits = splitDamageIntoHits(
55	    outcome.attackerDamage,
56	    pickHitCount(outcome.attackerDamage, attacker.maxHp, true),
57	    false,
58	  );
59	
60	  const rawBeats = interleaveHits(attackerHits, defenderHits);
61	  const enrichedBeats = injectGlanceBeats(rawBeats, outcome, attacker, defender);
62	
63	  let attackerHp = attacker.hp;
64	  let defenderHp = defender.hp;
65	
66	  const beats = enrichedBeats.map((beat, index) => {
67	    if (beat.actor === 'attacker') {
68	      defenderHp = Math.max(0, defenderHp - beat.damage);
69	    } else {
70	      attackerHp = Math.max(0, attackerHp - beat.damage);
71	    }
72	
73	    return {
74	      ...beat,
75	      attackerHpAfter: attackerHp,
76	      defenderHpAfter: defenderHp,
77	      intensity: computeBeatIntensity(beat, attacker, defender, index === enrichedBeats.length - 1),
78	    };
79	  });
80	
81	  return {
82	    beats,
83	    attackerEndHp,
84	    defenderEndHp,
85	  };
86	}
