88	function pickHitCount(totalDamage: number, targetMaxHp: number, isCounter: boolean): number {
89	  if (totalDamage <= 0) {
90	    return 0;
91	  }
92	
93	  const share = totalDamage / Math.max(1, targetMaxHp);
94	  let count = 1;
95	
96	  if (totalDamage >= 5 || share >= 0.28) {
97	    count += 1;
98	  }
99	  if (totalDamage >= 10 || share >= 0.58) {
100	    count += 1;
101	  }
102	  if (!isCounter && (totalDamage >= 15 || share >= 0.85)) {
103	    count += 1;
104	  }
105	
106	  return Math.max(1, Math.min(isCounter ? 3 : 4, count));
107	}
108	
109	function splitDamageIntoHits(totalDamage: number, hitCount: number, frontLoaded: boolean): number[] {
110	  if (totalDamage <= 0 || hitCount <= 0) {
111	    return [];
112	  }
113	
114	  const hits = Array.from({ length: hitCount }, () => Math.floor(totalDamage / hitCount));
115	  let remainder = totalDamage % hitCount;
116	
117	  for (let i = 0; i < hits.length && remainder > 0; i += 1) {
118	    const index = frontLoaded ? i : hits.length - 1 - i;
119	    hits[index] += 1;
120	    remainder -= 1;
121	  }
122	
123	  return hits.filter((damage) => damage > 0);
124	}
125	
126	function interleaveHits(attackerHits: number[], defenderHits: number[]): RawBeat[] {
127	  const beats: RawBeat[] = [];
128	  let attackerIndex = 0;
129	  let defenderIndex = 0;
130	  let nextActor: CombatBeatActor = 'attacker';
131	
132	  if (attackerHits.length > 0) {
133	    beats.push({ actor: 'attacker', kind: 'hit', damage: attackerHits[attackerIndex] });
134	    attackerIndex += 1;
135	    nextActor = 'defender';
136	  }
137	
138	  while (attackerIndex < attackerHits.length || defenderIndex < defenderHits.length) {
139	    if (nextActor === 'defender' && defenderIndex < defenderHits.length) {
140	      beats.push({ actor: 'defender', kind: 'hit', damage: defenderHits[defenderIndex] });
141	      defenderIndex += 1;
142	      nextActor = 'attacker';
143	      continue;
144	    }
145	
146	    if (nextActor === 'attacker' && attackerIndex < attackerHits.length) {
147	      beats.push({ actor: 'attacker', kind: 'hit', damage: attackerHits[attackerIndex] });
148	      attackerIndex += 1;
149	      nextActor = 'defender';
150	      continue;
151	    }
152	
153	    if (attackerIndex < attackerHits.length) {
154	      beats.push({ actor: 'attacker', kind: 'hit', damage: attackerHits[attackerIndex] });
155	      attackerIndex += 1;
156	      nextActor = 'defender';
157	      continue;
158	    }
159	
160	    if (defenderIndex < defenderHits.length) {
161	      beats.push({ actor: 'defender', kind: 'hit', damage: defenderHits[defenderIndex] });
162	      defenderIndex += 1;
163	      nextActor = 'attacker';
164	    }
165	  }
166	
167	  if (beats.length === 0 && defenderHits.length > 0) {
168	    return defenderHits.map((damage) => ({ actor: 'defender', kind: 'hit', damage }));
169	  }
170	
171	  return beats;
172	}
173	
174	function injectGlanceBeats(
175	  beats: RawBeat[],
176	  outcome: CombatAnimationOutcome,
177	  attacker: UnitView,
178	  defender: UnitView,
179	): RawBeat[] {
180	  const duelRange = Math.max(attacker.range ?? 1, defender.range ?? 1);
181	  const bothSurvive = !outcome.attackerDestroyed && !outcome.defenderDestroyed;
182	  const closeMatchup = getCombatCloseness(attacker, defender) >= 0.7;
183	
184	  const minimumBeatCount = duelRange <= 1
185	    ? (bothSurvive && closeMatchup ? 4 : 3)
186	    : 2;
187	
188	  const enriched: RawBeat[] = [...beats];
189	
190	  if (outcome.defenderDamage === 0 && outcome.attackerDamage > 0) {
191	    enriched.unshift({ actor: 'attacker', kind: 'glance', damage: 0 });
192	  }
193	
194	  if (outcome.attackerDamage === 0 && outcome.defenderDamage === 0 && enriched.length === 0) {
195	    enriched.push({ actor: 'attacker', kind: 'glance', damage: 0 });
196	  }
197	
198	  if (enriched.length === 0) {
199	    return enriched;
200	  }
201	
202	  let insertIndex = 1;
203	  while (enriched.length < minimumBeatCount) {
204	    const previousActor = enriched[Math.max(0, insertIndex - 1)]?.actor ?? 'defender';
205	    enriched.splice(insertIndex, 0, {
206	      actor: previousActor === 'attacker' ? 'defender' : 'attacker',
207	      kind: 'glance',
208	      damage: 0,
209	    });
210	    insertIndex = Math.min(enriched.length, insertIndex + 2);
211	  }
212	
213	  return enriched;
214	}
215	
216	function getCombatCloseness(attacker: UnitView, defender: UnitView): number {
217	  const attackerPower = attacker.attack + attacker.effectiveDefense;
218	  const defenderPower = defender.attack + defender.effectiveDefense;
219	  const spread = Math.abs(attackerPower - defenderPower);
220	  const total = Math.max(1, attackerPower + defenderPower);
221	  return 1 - Math.min(1, spread / total);
222	}
223	
224	function computeBeatIntensity(
225	  beat: RawBeat,
226	  attacker: UnitView,
227	  defender: UnitView,
228	  isLastBeat: boolean,
229	): number {
230	  if (beat.kind === 'glance') {
231	    return 0.78;
232	  }
233	
234	  const targetMaxHp = beat.actor === 'attacker' ? defender.maxHp : attacker.maxHp;
235	  const damageShare = beat.damage / Math.max(1, targetMaxHp);
236	  const actorPower = beat.actor === 'attacker'
237	    ? attacker.attack + attacker.effectiveDefense
238	    : defender.attack + defender.effectiveDefense;
239	  const targetPower = beat.actor === 'attacker'
240	    ? defender.attack + defender.effectiveDefense
241	    : attacker.attack + attacker.effectiveDefense;
242	  const statEdge = actorPower / Math.max(1, targetPower);
243	  const finisherBonus = isLastBeat ? 0.08 : 0;
244	
245	  return clamp(
246	    0.8 + damageShare * 1.45 + Math.min(0.18, Math.max(-0.06, (statEdge - 1) * 0.12)) + finisherBonus,
247	    MIN_INTENSITY,
248	    MAX_INTENSITY,
249	  );
250	}
251	
252	function clamp(value: number, min: number, max: number): number {
253	  return Math.max(min, Math.min(max, value));
254	}

