510	    allSprites.push(attFinal, defFinal, attMarker, defMarker, attHpBar.container, defHpBar.container);
511	
512	    script.beats
513	      .filter((beat) => beat.kind === 'hit' && beat.damage > 0)
514	      .slice(-3)
515	      .forEach((beat, index) => {
516	        const targetPos = beat.actor === 'attacker' ? defPos : attPos;
