554	  private cloneSprite(unit: UnitView, x: number, y: number): Phaser.GameObjects.Image {
555	    const dir = ((unit.facing % 8) + 8) % 8;
556	    const isRearFacing = dir === 0 || dir === 1 || dir === 6 || dir === 7;
557	
558	    let texture: ReturnType<typeof getUnitTextureSpec>;
559	    if (isRearFacing) {
560	      texture = getUnitRearTextureSpec(unit.spriteKey) ?? getUnitTextureSpec(unit.spriteKey);
561	    } else {
562	      texture = getUnitTextureSpec(unit.spriteKey);
563	    }
564	
565	    const sprite = texture.kind === 'sheet'
566	      ? this.scene.add.image(x, y - texture.yOffset, texture.texture, texture.frame)
567	      : this.scene.add.image(x, y - texture.yOffset, texture.texture);
568	    sprite
569	      .setOrigin(0.5, 1)
570	      .setDisplaySize(texture.displayWidth, texture.displayHeight)
571	      .setAlpha(unit.acted ? 0.58 : 1);
572	
573	    if (dir === 1 || dir === 2 || dir === 5) {
574	      sprite.setFlipX(true);
575	    } else if (dir === 6) {
576	      sprite.setFlipX(false);
577	    }
578	
579	    return sprite;
580	  }
