582	  private createHpBar(pos: Point, hp: number, maxHp: number): HpBar {
583	    const width = 28;
584	    const container = this.scene.add.container(pos.x, pos.y + 8);
585	    const track = this.scene.add.rectangle(0, 0, width, 4, 0x261d15, 0.8).setOrigin(0.5, 0.5);
586	    const fill = this.scene.add.rectangle(-width / 2, 0, width, 4, 0x8fd694, 0.95).setOrigin(0, 0.5);
587	    container.add([track, fill]);
588	
589	    const setRatio = (ratio: number) => {
590	      const clampedRatio = Math.max(0, Math.min(1, ratio));
591	      fill.setScale(Math.max(0.06, clampedRatio), 1);
592	      fill.setFillStyle(clampedRatio < 0.35 ? 0xe05b3f : 0x8fd694, 0.95);
593	    };
594	
595	    setRatio(maxHp > 0 ? hp / maxHp : 0);
596	
597	    return {
598	      container,
599	      track,
600	      fill,
601	      setRatio,
602	    };
603	  }
