626	  private normalize(vector: Point): Point {
627	    const length = Math.hypot(vector.x, vector.y);
628	    if (length === 0) {
629	      return { x: 1, y: 0 };
630	    }
631	    return {
632	      x: vector.x / length,
633	      y: vector.y / length,
634	    };
635	  }
