375	  private bootstrap(source: PlayStateSource) {
376	    let state = source.type === 'serialized'
377	      ? deserializeGameState(source.payload)
378	      : buildMvpScenario(source.seed ?? 42, {
379	          registry: this.registry,
380	          mapMode: source.mapMode ?? this.mapMode,
381	          mapSize: source.mapSize ?? this.mapSize,
382	          selectedFactionIds: source.selectedFactionIds ?? this.selectedFactions,
383	          settlerStartFactionIds: Array.from(this.humanControlledFactionIds),
384	        });
