557	  /** Clear move queue on a specific unit if one exists. Returns updated state. */
558	  private clearMoveQueueOnUnit(state: GameState, unitId: UnitId): GameState {
559	    const unit = state.units.get(unitId);
560	    if (!unit?.moveQueueDestination) return state;
561	    const newUnits = new Map(state.units);
562	    newUnits.set(unitId, { ...unit, moveQueueDestination: undefined });
563	    return { ...state, units: newUnits };
564	  }
