646	  /**
647	   * Phase 1: Resolve combat mathematically but do NOT mutate game state.
648	   * Returns PendingCombat data for the animator to use, or null if illegal.
649	   */
650	  resolveAttack(attackerId: UnitId, defenderId: UnitId): PendingCombat | null {
651	    const preview = previewCombatAction(this.state, this.registry, attackerId, defenderId);
652	    if (!preview) {
653	      return null;
654	    }
655	
656	    return this.buildPendingCombat(preview);
657	  }
