659	  private buildPendingCombat(preview: CombatActionPreview): PendingCombat {
660	    const combatEvent: ReplayCombatEvent = {
661	      round: preview.round,
662	      attackerUnitId: preview.attackerId,
663	      defenderUnitId: preview.defenderId,
664	      attackerFactionId: preview.attackerFactionId,
665	      defenderFactionId: preview.defenderFactionId,
666	      attackerPrototypeName: preview.attackerPrototypeName,
667	      defenderPrototypeName: preview.defenderPrototypeName,
668	      attackerDamage: preview.result.attackerDamage,
669	      defenderDamage: preview.result.defenderDamage,
670	      attackerDestroyed: preview.result.attackerDestroyed,
671	      defenderDestroyed: preview.result.defenderDestroyed,
672	      attackerRouted: preview.result.attackerRouted,
673	      defenderRouted: preview.result.defenderRouted,
674	      attackerFled: preview.result.attackerFled,
675	      defenderFled: preview.result.defenderFled,
676	      summary: `${preview.attackerPrototypeName} attacked ${preview.defenderPrototypeName}`,
677	      breakdown: {
678	        modifiers: {
679	          flankingBonus: preview.result.flankingBonus,
680	          stealthAmbushBonus: preview.attackerWasStealthed ? 0.5 : 0,
681	          rearAttackBonus: preview.result.rearAttackBonus,
682	          finalAttackStrength: preview.result.attackStrength,
683	          finalDefenseStrength: preview.result.defenseStrength,
684	        },
685	        outcome: {
686	          attackerDamage: preview.result.attackerDamage,
687	          defenderDamage: preview.result.defenderDamage,
688	        },
689	        triggeredEffects: preview.triggeredEffects,
690	      },
691	    };
692	
693	    return {
694	      attackerId: preview.attackerId,
695	      defenderId: preview.defenderId,
696	      preview,
697	      result: preview.result,
698	      combatEvent,
699	    };
700	  }
